import { useCharacterStore } from '@/store/characterStore';
import type { Character } from '@/types';
import { StickyNote } from 'lucide-react';

interface Props {
  character: Character;
}

export function Notes({ character }: Props) {
  const updateCharacter = useCharacterStore(s => s.updateCharacter);

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-2 flex items-center gap-1.5 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">
        <StickyNote className="h-3.5 w-3.5" /> Notes
      </h3>
      <textarea
        value={character.notes}
        onChange={e => updateCharacter(character.id, { notes: e.target.value })}
        placeholder="Session notes, reminders, homebrew rules..."
        className="min-h-[120px] w-full resize-y rounded border border-ink-200 bg-white p-2 text-sm text-ink-700 outline-none placeholder:text-ink-300 focus:border-ink-400 dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:placeholder:text-ink-400 dark:focus:border-ink-400"
      />
    </div>
  );
}
