/**
 * Simple class accessors for multiclass support.
 * ZERO dependencies on @/data or characterStore to avoid circular imports.
 * These only depend on @/types.
 */

import type { Character, ClassEntry, AbilityKey } from '@/types';

// ---- Static class data (no external imports) ----

const CLASS_INFO: Record<string, { name: string; hitDie: number }> = {
  barbarian: { name: 'Barbarian', hitDie: 12 }, bard: { name: 'Bard', hitDie: 8 },
  cleric: { name: 'Cleric', hitDie: 8 }, druid: { name: 'Druid', hitDie: 8 },
  fighter: { name: 'Fighter', hitDie: 10 }, monk: { name: 'Monk', hitDie: 8 },
  paladin: { name: 'Paladin', hitDie: 10 }, ranger: { name: 'Ranger', hitDie: 10 },
  rogue: { name: 'Rogue', hitDie: 8 }, sorcerer: { name: 'Sorcerer', hitDie: 6 },
  warlock: { name: 'Warlock', hitDie: 8 }, wizard: { name: 'Wizard', hitDie: 6 },
};

// ---- Core Accessors ----

export function getClasses(char: Character): ClassEntry[] {
  if (char.classes && char.classes.length > 0) return char.classes;
  return [{
    classKey: char.classKey,
    subclassKey: char.subclassKey,
    classLevel: char.level,
    hitDiceCurrent: char.hitDice?.current ?? char.level,
  }];
}

export function getCharacterLevel(char: Character): number {
  return getClasses(char).reduce((sum, c) => sum + c.classLevel, 0);
}

export function getPrimaryClass(char: Character): ClassEntry {
  return getClasses(char)[0];
}

export function hasClassLevel(char: Character, classKey: string, minLevel = 1): boolean {
  const entry = getClasses(char).find(c => c.classKey === classKey);
  return entry ? entry.classLevel >= minLevel : false;
}

export function getClassLevel(char: Character, classKey: string): number {
  return getClasses(char).find(c => c.classKey === classKey)?.classLevel ?? 0;
}

export function getClassEntry(char: Character, classKey: string): ClassEntry | undefined {
  return getClasses(char).find(c => c.classKey === classKey);
}

export interface HitDicePool {
  classKey: string;
  className: string;
  dieType: number;
  current: number;
  max: number;
}

export function getHitDiceByClass(char: Character): HitDicePool[] {
  return getClasses(char).map(entry => {
    const info = CLASS_INFO[entry.classKey];
    return {
      classKey: entry.classKey,
      className: info?.name ?? entry.classKey,
      dieType: info?.hitDie ?? 8,
      current: entry.hitDiceCurrent,
      max: entry.classLevel,
    };
  });
}

// ---- Multiclass Prerequisites ----

const MULTICLASS_PREREQS: Record<string, { abilities: AbilityKey[]; min: number }> = {
  barbarian: { abilities: ['str'], min: 13 }, bard: { abilities: ['cha'], min: 13 },
  cleric: { abilities: ['wis'], min: 13 }, druid: { abilities: ['wis'], min: 13 },
  fighter: { abilities: ['str'], min: 13 }, monk: { abilities: ['dex', 'wis'], min: 13 },
  paladin: { abilities: ['str', 'cha'], min: 13 }, ranger: { abilities: ['dex', 'wis'], min: 13 },
  rogue: { abilities: ['dex'], min: 13 }, sorcerer: { abilities: ['cha'], min: 13 },
  warlock: { abilities: ['cha'], min: 13 }, wizard: { abilities: ['int'], min: 13 },
};

export function meetsMulticlassPrereqs(
  char: Character, targetClassKey: string, abilityTotals: Record<AbilityKey, number>
): { met: boolean; reason: string } {
  const reasons: string[] = [];
  for (const entry of getClasses(char)) {
    const prereq = MULTICLASS_PREREQS[entry.classKey];
    if (!prereq) continue;
    if (entry.classKey === 'fighter') {
      if (abilityTotals.str < 13 && abilityTotals.dex < 13)
        reasons.push(`Need STR 13 or DEX 13 to multiclass from Fighter (have STR ${abilityTotals.str}, DEX ${abilityTotals.dex})`);
    } else {
      for (const ab of prereq.abilities)
        if (abilityTotals[ab] < prereq.min)
          reasons.push(`Need ${ab.toUpperCase()} ${prereq.min} to multiclass from ${CLASS_INFO[entry.classKey]?.name ?? entry.classKey} (have ${abilityTotals[ab]})`);
    }
  }
  const targetPrereq = MULTICLASS_PREREQS[targetClassKey];
  if (targetPrereq) {
    if (targetClassKey === 'fighter') {
      if (abilityTotals.str < 13 && abilityTotals.dex < 13)
        reasons.push(`Need STR 13 or DEX 13 to multiclass into Fighter`);
    } else {
      for (const ab of targetPrereq.abilities)
        if (abilityTotals[ab] < targetPrereq.min)
          reasons.push(`Need ${ab.toUpperCase()} ${targetPrereq.min} to multiclass into ${CLASS_INFO[targetClassKey]?.name ?? targetClassKey} (have ${abilityTotals[ab]})`);
    }
  }
  return reasons.length === 0 ? { met: true, reason: '' } : { met: false, reason: reasons.join('. ') };
}

// ---- Multiclass Proficiencies ----

export interface MulticlassProfs { armor: string[]; weapons: string[]; tools: string[]; skills: number }
const MC_PROFS: Record<string, MulticlassProfs> = {
  barbarian: { armor: ['Shields'], weapons: ['Simple Weapons', 'Martial Weapons'], tools: [], skills: 0 },
  bard: { armor: ['Light Armor'], weapons: [], tools: [], skills: 1 },
  cleric: { armor: ['Light Armor', 'Medium Armor', 'Shields'], weapons: [], tools: [], skills: 0 },
  druid: { armor: ['Light Armor', 'Medium Armor', 'Shields'], weapons: [], tools: [], skills: 0 },
  fighter: { armor: ['Light Armor', 'Medium Armor', 'Shields'], weapons: ['Simple Weapons', 'Martial Weapons'], tools: [], skills: 0 },
  monk: { armor: [], weapons: ['Simple Weapons', 'Shortswords'], tools: [], skills: 0 },
  paladin: { armor: ['Light Armor', 'Medium Armor', 'Shields'], weapons: ['Simple Weapons', 'Martial Weapons'], tools: [], skills: 0 },
  ranger: { armor: ['Light Armor', 'Medium Armor', 'Shields'], weapons: ['Simple Weapons', 'Martial Weapons'], tools: [], skills: 1 },
  rogue: { armor: ['Light Armor'], weapons: [], tools: ["Thieves' Tools"], skills: 1 },
  sorcerer: { armor: [], weapons: [], tools: [], skills: 0 },
  warlock: { armor: ['Light Armor'], weapons: ['Simple Weapons'], tools: [], skills: 0 },
  wizard: { armor: [], weapons: [], tools: [], skills: 0 },
};
export function getMulticlassProficiencies(classKey: string): MulticlassProfs {
  return MC_PROFS[classKey] ?? { armor: [], weapons: [], tools: [], skills: 0 };
}

// ---- Multiclass Spell Slots ----

const FULL_CASTER_SLOTS: Record<string, number[]> = {
  '1': [2,0,0,0,0,0,0,0,0], '2': [3,0,0,0,0,0,0,0,0], '3': [4,2,0,0,0,0,0,0,0],
  '4': [4,3,0,0,0,0,0,0,0], '5': [4,3,2,0,0,0,0,0,0], '6': [4,3,3,0,0,0,0,0,0],
  '7': [4,3,3,1,0,0,0,0,0], '8': [4,3,3,2,0,0,0,0,0], '9': [4,3,3,3,1,0,0,0,0],
  '10': [4,3,3,3,2,0,0,0,0], '11': [4,3,3,3,2,1,0,0,0], '12': [4,3,3,3,2,1,0,0,0],
  '13': [4,3,3,3,2,1,1,0,0], '14': [4,3,3,3,2,1,1,0,0], '15': [4,3,3,3,2,1,1,1,0],
  '16': [4,3,3,3,2,1,1,1,0], '17': [4,3,3,3,2,1,1,1,1], '18': [4,3,3,3,3,1,1,1,1],
  '19': [4,3,3,3,3,2,1,1,1], '20': [4,3,3,3,3,2,2,1,1],
};

const PACT_MAGIC: Record<string, { slots: number; slotLevel: number }> = {
  '1': { slots: 1, slotLevel: 1 }, '2': { slots: 2, slotLevel: 1 },
  '3': { slots: 2, slotLevel: 2 }, '4': { slots: 2, slotLevel: 2 },
  '5': { slots: 2, slotLevel: 3 }, '6': { slots: 2, slotLevel: 3 },
  '7': { slots: 2, slotLevel: 4 }, '8': { slots: 2, slotLevel: 4 },
  '9': { slots: 2, slotLevel: 5 }, '10': { slots: 2, slotLevel: 5 },
  '11': { slots: 3, slotLevel: 5 }, '12': { slots: 3, slotLevel: 5 },
  '13': { slots: 3, slotLevel: 5 }, '14': { slots: 3, slotLevel: 5 },
  '15': { slots: 3, slotLevel: 5 }, '16': { slots: 3, slotLevel: 5 },
  '17': { slots: 4, slotLevel: 5 }, '18': { slots: 4, slotLevel: 5 },
  '19': { slots: 4, slotLevel: 5 }, '20': { slots: 4, slotLevel: 5 },
};

const CASTER_TYPE: Record<string, string> = {
  bard: 'full', cleric: 'full', druid: 'full', sorcerer: 'full', wizard: 'full',
  paladin: 'half', ranger: 'half', warlock: 'pact',
};
const THIRD_CASTER_SUBCLASSES = ['eldritch-knight', 'arcane-trickster'];

export function getMulticlassSpellSlots(char: Character): {
  slots: Record<number, { current: number; max: number }>;
  pactSlots: { current: number; max: number; slotLevel: number } | null;
} {
  const classes = getClasses(char);
  let combinedCasterLevel = 0;
  let pactSlots: { current: number; max: number; slotLevel: number } | null = null;

  for (const entry of classes) {
    if (entry.classKey === 'warlock') {
      const pact = PACT_MAGIC[String(entry.classLevel)];
      if (pact) {
        pactSlots = char.pactSlots ?? { current: pact.slots, max: pact.slots, slotLevel: pact.slotLevel };
        pactSlots = { ...pactSlots, max: pact.slots, slotLevel: pact.slotLevel };
      }
      continue;
    }
    if (entry.subclassKey && THIRD_CASTER_SUBCLASSES.includes(entry.subclassKey)) {
      combinedCasterLevel += Math.floor(entry.classLevel / 3);
      continue;
    }
    const casterType = CASTER_TYPE[entry.classKey];
    if (casterType === 'full') combinedCasterLevel += entry.classLevel;
    else if (casterType === 'half' && entry.classLevel >= 2) combinedCasterLevel += Math.floor(entry.classLevel / 2);
  }

  const slots: Record<number, { current: number; max: number }> = {};
  if (combinedCasterLevel > 0) {
    const row = FULL_CASTER_SLOTS[String(combinedCasterLevel)];
    if (row) {
      row.forEach((count, idx) => {
        if (count > 0) {
          const existing = char.spellSlots[idx + 1];
          slots[idx + 1] = { current: existing?.current ?? count, max: count };
        }
      });
    }
  }
  return { slots, pactSlots };
}
