import React, { useState } from 'react';
import { useCharacterStore } from '@/store/characterStore';
import { equipmentCatalog, armor as armorData, allWeapons, magicItems } from '@/data';
import type { MagicItem } from '@/data';
import type { Character, ComputedStats, InventoryItem } from '@/types';
import { Package, Plus, X, Weight, Search, ChevronDown, ChevronUp, Sparkles, Info } from 'lucide-react';
import type { MagicItemVariant } from '@/data';

const allArmorNames = new Set([
  ...armorData.light, ...armorData.medium, ...armorData.heavy
].map(a => a.name.toLowerCase()));
const allWeaponNames = new Set(allWeapons.map(w => w.name.toLowerCase()));

/** Strip magic suffixes like " +1", " +2", " +3" to find the base item name */
function getBaseItemName(name: string): string {
  return name.toLowerCase().replace(/\s*\+\d+$/, '').trim();
}

// Named magic weapons that should be equippable as weapons
const NAMED_MAGIC_WEAPONS: Record<string, string> = {
  'berserker axe': 'battleaxe', 'dagger of venom': 'dagger', 'dancing sword': 'longsword',
  'defender': 'longsword', 'dragon slayer': 'longsword', 'dwarven thrower': 'warhammer',
  'giant slayer': 'longsword', 'hammer of thunderbolts': 'maul', 'holy avenger': 'longsword',
  'javelin of lightning': 'javelin', 'luck blade': 'shortsword', 'mace of disruption': 'mace',
  'mace of smiting': 'mace', 'mace of terror': 'mace', 'nine lives stealer': 'longsword',
  'oathbow': 'longbow', 'scimitar of speed': 'scimitar', 'sun blade': 'longsword',
  'sword of answering': 'longsword', 'sword of life stealing': 'longsword',
  'sword of sharpness': 'longsword', 'sword of vengeance': 'longsword',
  'sword of wounding': 'longsword', 'trident of fish command': 'trident',
  'vicious weapon': 'longsword', 'vorpal sword': 'greatsword', 'weapon of warning': 'longsword',
};
// Also match Flame Tongue/Frost Brand with weapon suffix: "Flame Tongue Longsword" etc.
function resolveWeaponBase(name: string): string | null {
  const base = getBaseItemName(name);
  if (allWeaponNames.has(base)) return base;
  const named = NAMED_MAGIC_WEAPONS[base];
  if (named) return named;
  // "Flame Tongue Longsword" → "Longsword"
  for (const prefix of ['flame tongue', 'frost brand']) {
    if (base.startsWith(prefix + ' ')) {
      const suffix = base.slice(prefix.length + 1);
      if (allWeaponNames.has(suffix)) return suffix;
    }
  }
  return null;
}

const isArmor = (name: string) => allArmorNames.has(getBaseItemName(name));
const isWeapon = (name: string) => resolveWeaponBase(name) !== null;
const isShield = (name: string) => getBaseItemName(name) === 'shield';

type EquipSlot = 'armor' | 'mainhand' | 'offhand' | null;

function getEquipOptions(item: InventoryItem): { slot: EquipSlot; label: string }[] {
  const name = item.name;
  if (isArmor(name)) return [{ slot: 'armor', label: 'Armor' }];
  if (isShield(name)) return [{ slot: 'offhand', label: 'OH' }];
  if (isWeapon(name)) {
    const base = resolveWeaponBase(name);
    const weapon = base ? allWeapons.find(w => w.name.toLowerCase() === base) : null;
    const isTwoHanded = weapon?.properties.some(p => p.toLowerCase().includes('two-handed'));
    if (isTwoHanded) return [{ slot: 'mainhand', label: '2H' }];
    return [
      { slot: 'mainhand', label: 'MH' },
      { slot: 'offhand', label: 'OH' },
    ];
  }
  return [];
}

interface Props {
  character: Character;
  stats: ComputedStats;
}

export function Inventory({ character, stats }: Props) {
  const { addInventoryItem, removeInventoryItem, updateInventoryItem, updateCharacter } = useCharacterStore();
  const [showCatalog, setShowCatalog] = useState(false);
  const [catalogSearch, setCatalogSearch] = useState('');
  const [expandedCategory, setExpandedCategory] = useState<string | null>(null);
  const [showCustom, setShowCustom] = useState(false);
  const [showMagic, setShowMagic] = useState(false);
  const [magicSearch, setMagicSearch] = useState('');
  const [magicRarityFilter, setMagicRarityFilter] = useState<string | null>(null);
  const [magicTypeFilter, setMagicTypeFilter] = useState<string | null>(null);
  const [expandedMagicItem, setExpandedMagicItem] = useState<string | null>(null);
  const [variantPicker, setVariantPicker] = useState<MagicItem | null>(null);
  const [expandedItemInfo, setExpandedItemInfo] = useState<string | null>(null);
  const [newItem, setNewItem] = useState({ name: '', quantity: 1, weight: 0 });

  const overEncumbered = stats.currentCarryWeight > stats.carryCapacity;

  // Sort inventory alphabetically
  const sortedInventory = [...character.inventory].sort((a, b) => a.name.localeCompare(b.name));

  // Filter catalog by search
  const filteredCatalog = catalogSearch.trim()
    ? equipmentCatalog
        .map(cat => ({
          ...cat,
          items: cat.items.filter(i =>
            i.name.toLowerCase().includes(catalogSearch.toLowerCase())
          ),
        }))
        .filter(cat => cat.items.length > 0)
    : equipmentCatalog;

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <div className="flex items-center justify-between">
        <h3 className="flex items-center gap-1.5 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">
          <Package className="h-3.5 w-3.5" /> Inventory
        </h3>
        <span className={`flex items-center gap-1 text-xs font-medium ${overEncumbered ? 'text-crimson dark:text-crimson-light' : 'text-ink-400 dark:text-parchment-400'}`}>
          <Weight className="h-3 w-3" />
          {stats.currentCarryWeight.toFixed(1)} / {stats.carryCapacity} lbs
        </span>
      </div>

      {/* Currency */}
      <div className="mt-2 flex gap-2">
        {(['copper', 'silver', 'electrum', 'gold', 'platinum'] as const).map(coin => (
          <div key={coin} className="flex flex-col items-center">
            <input
              type="number"
              value={character[coin]}
              onChange={e => updateCharacter(character.id, { [coin]: parseInt(e.target.value) || 0 })}
              className="w-14 rounded border border-ink-200 bg-white px-1 py-0.5 text-center text-sm outline-none focus:border-gold dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-gold-light"
              min="0"
            />
            <span className="text-[10px] uppercase text-ink-400 dark:text-parchment-400">{coin.slice(0, 2)}</span>
          </div>
        ))}
      </div>

      {/* Item List (sorted alphabetically) */}
      <div className="mt-3 space-y-1">
        {sortedInventory.map(item => (
          <React.Fragment key={item.id}>
          <div className="flex items-center gap-2 rounded px-1 py-0.5 text-sm hover:bg-parchment-50 dark:hover:bg-ink-700">
            <input
              type="checkbox"
              checked={item.equipped ?? false}
              onChange={e => {
                const equipping = e.target.checked;
                if (equipping) {
                  const options = getEquipOptions(item);
                  const defaultSlot = options[0]?.slot ?? null;
                  // Unequip conflicting items in the same slot
                  if (defaultSlot) {
                    character.inventory.forEach(other => {
                      if (other.id !== item.id && other.equipped && other.equipSlot === defaultSlot) {
                        updateInventoryItem(character.id, other.id, { equipped: false, equipSlot: null });
                      }
                    });
                    // Two-handed weapons also clear offhand
                    const weapon = (() => { const b = resolveWeaponBase(item.name); return b ? allWeapons.find(w => w.name.toLowerCase() === b) : null; })();
                    if (weapon?.properties.some(p => p.toLowerCase().includes('two-handed')) && defaultSlot === 'mainhand') {
                      character.inventory.forEach(other => {
                        if (other.id !== item.id && other.equipped && other.equipSlot === 'offhand') {
                          updateInventoryItem(character.id, other.id, { equipped: false, equipSlot: null });
                        }
                      });
                    }
                  }
                  updateInventoryItem(character.id, item.id, { equipped: true, equipSlot: defaultSlot });
                } else {
                  updateInventoryItem(character.id, item.id, { equipped: false, equipSlot: null });
                }
              }}
              className="h-3.5 w-3.5 rounded border-ink-300 accent-crimson"
              title={isArmor(item.name) ? 'Equip armor (affects AC)' : isShield(item.name) ? 'Equip shield (+2 AC)' : isWeapon(item.name) ? 'Equip weapon' : 'Equipped'}
            />
            <span className="flex-1 text-ink-700 dark:text-parchment-100">
              {item.name}
              {item.equipped && item.equipSlot && (
                <span className={`ml-1 rounded px-1 py-0.5 text-[9px] font-bold uppercase ${
                  item.equipSlot === 'mainhand' ? 'bg-crimson/10 text-crimson dark:bg-crimson-light/20 dark:text-crimson-light'
                    : item.equipSlot === 'offhand' ? 'bg-royal-blue/10 text-royal-blue dark:bg-royal-light/20 dark:text-royal-light'
                    : 'bg-gold/10 text-gold dark:bg-gold-light/20 dark:text-gold-light'
                }`}>
                  {item.equipSlot === 'mainhand' ? 'MH' : item.equipSlot === 'offhand' ? 'OH' : 'ARM'}
                </span>
              )}
              {item.equipped && item.equipSlot && isWeapon(item.name) && !((() => { const b = resolveWeaponBase(item.name); return b ? allWeapons.find(w => w.name.toLowerCase() === b) : null; })()?.properties.some(p => p.toLowerCase().includes('two-handed'))) && (
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    const newSlot = item.equipSlot === 'mainhand' ? 'offhand' : 'mainhand';
                    // Unequip whatever is in the target slot
                    character.inventory.forEach(other => {
                      if (other.id !== item.id && other.equipped && other.equipSlot === newSlot) {
                        updateInventoryItem(character.id, other.id, { equipped: false, equipSlot: null });
                      }
                    });
                    updateInventoryItem(character.id, item.id, { equipSlot: newSlot as EquipSlot });
                  }}
                  className="ml-0.5 text-[9px] text-ink-400 hover:text-ink-600 dark:text-parchment-400 dark:hover:text-parchment-200"
                  title="Swap hand"
                >⇄</button>
              )}
            </span>
            <input
              type="number"
              value={item.quantity}
              onChange={e => updateInventoryItem(character.id, item.id, { quantity: parseInt(e.target.value) || 1 })}
              className="w-10 rounded border border-ink-200 bg-white px-1 py-0.5 text-center text-xs outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
              min="1"
            />
            <span className="w-12 text-right text-xs text-ink-400 dark:text-parchment-400">{(item.weight * item.quantity).toFixed(1)} lb</span>
            {item.description && (
              <button
                onClick={() => setExpandedItemInfo(expandedItemInfo === item.id ? null : item.id)}
                className={`rounded-full p-0.5 transition-colors ${
                  expandedItemInfo === item.id
                    ? 'text-gold dark:text-gold-light'
                    : 'text-ink-300 hover:text-ink-500 dark:text-ink-400 dark:hover:text-parchment-200'
                }`}
                title="Item details"
              >
                <Info className="h-3 w-3" />
              </button>
            )}
            <button onClick={() => removeInventoryItem(character.id, item.id)} className="text-ink-300 hover:text-crimson dark:text-ink-400 dark:hover:text-crimson-light">
              <X className="h-3 w-3" />
            </button>
          </div>
          {expandedItemInfo === item.id && (
            <div className="ml-6 mb-1 rounded border border-ink-100 bg-parchment-50 p-2 text-xs leading-relaxed dark:border-ink-600 dark:bg-ink-700">
              {/* Charge tracker */}
              {item.chargesMax != null && (
                <div className="mb-2 rounded bg-gold/5 p-2 dark:bg-gold-light/10">
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] font-semibold uppercase tracking-wider text-gold dark:text-gold-light">
                      {item.charges ?? 0} / {item.chargesMax} used
                    </span>
                    {item.chargesMax <= 10 ? (
                      <div className="flex gap-0.5">
                        {Array.from({ length: item.chargesMax }, (_, i) => (
                          <button
                            key={i}
                            onClick={() => {
                              const current = item.charges ?? 0;
                              const next = i < current ? i : i + 1;
                              updateInventoryItem(character.id, item.id, { charges: next });
                            }}
                            className={`h-3 w-3 rounded-sm border transition-colors ${
                              i < (item.charges ?? 0)
                                ? 'border-gold bg-gold dark:border-gold-light dark:bg-gold-light'
                                : 'border-ink-300 bg-white dark:border-ink-500 dark:bg-ink-600'
                            }`}
                            title={`${i < (item.charges ?? 0) ? 'Clear' : 'Fill'} slot ${i + 1}`}
                          />
                        ))}
                      </div>
                    ) : (
                      <input
                        type="number"
                        value={item.charges ?? 0}
                        onChange={e => updateInventoryItem(character.id, item.id, { charges: Math.min(item.chargesMax!, Math.max(0, parseInt(e.target.value) || 0)) })}
                        className="w-14 rounded border border-gold/30 bg-white px-1 py-0.5 text-center text-xs outline-none dark:border-gold-light/30 dark:bg-ink-600 dark:text-parchment-100"
                        min={0}
                        max={item.chargesMax}
                      />
                    )}
                    <button
                      onClick={() => updateInventoryItem(character.id, item.id, { charges: 0 })}
                      className="text-[9px] text-ink-400 hover:text-ink-600 dark:text-parchment-400 dark:hover:text-parchment-200"
                    >
                      Reset
                    </button>
                  </div>
                  <input
                    type="text"
                    value={item.chargeNote ?? ''}
                    onChange={e => updateInventoryItem(character.id, item.id, { chargeNote: e.target.value })}
                    placeholder="Notes (e.g. Shield, Misty Step)"
                    className="mt-1 w-full rounded border border-gold/20 bg-white px-2 py-0.5 text-xs outline-none placeholder:text-ink-300 dark:border-gold-light/20 dark:bg-ink-600 dark:text-parchment-100 dark:placeholder:text-ink-400"
                  />
                </div>
              )}
              {item.description && (
                <div className="text-ink-600 whitespace-pre-line dark:text-parchment-200">
                  {item.description}
                </div>
              )}
            </div>
          )}
        </React.Fragment>
        ))}
        {sortedInventory.length === 0 && !showCatalog && (
          <p className="py-2 text-center text-xs text-ink-400 dark:text-parchment-400">No items — add from catalog or custom</p>
        )}
      </div>

      {/* Add buttons */}
      <div className="mt-3 flex gap-2">
        <button
          onClick={() => { setShowCatalog(!showCatalog); setShowCustom(false); setShowMagic(false); }}
          className={`flex flex-1 items-center justify-center gap-1 rounded-lg border px-3 py-1.5 text-xs font-medium transition-colors ${
            showCatalog
              ? 'border-crimson/30 bg-crimson/5 text-crimson dark:border-crimson-light/30 dark:bg-crimson-light/10 dark:text-crimson-light'
              : 'border-ink-200 text-ink-500 hover:bg-parchment-50 dark:border-ink-600 dark:text-parchment-300 dark:hover:bg-ink-700'
          }`}
        >
          <Package className="h-3 w-3" />
          {showCatalog ? 'Close Catalog' : 'Add from Catalog'}
        </button>
        {magicItems.length > 0 && (
          <button
            onClick={() => { setShowMagic(!showMagic); setShowCatalog(false); setShowCustom(false); }}
            className={`flex items-center gap-1 rounded-lg border px-3 py-1.5 text-xs font-medium transition-colors ${
              showMagic
                ? 'border-gold/30 bg-gold/5 text-gold dark:border-gold-light/30 dark:bg-gold-light/10 dark:text-gold-light'
                : 'border-ink-200 text-ink-500 hover:bg-parchment-50 dark:border-ink-600 dark:text-parchment-300 dark:hover:bg-ink-700'
            }`}
          >
            <Sparkles className="h-3 w-3" />
            {showMagic ? 'Close Magic' : 'Magic Find'}
          </button>
        )}
        <button
          onClick={() => { setShowCustom(!showCustom); setShowCatalog(false); setShowMagic(false); }}
          className={`flex items-center gap-1 rounded-lg border px-3 py-1.5 text-xs font-medium transition-colors ${
            showCustom
              ? 'border-crimson/30 bg-crimson/5 text-crimson dark:border-crimson-light/30 dark:bg-crimson-light/10 dark:text-crimson-light'
              : 'border-ink-200 text-ink-500 hover:bg-parchment-50 dark:border-ink-600 dark:text-parchment-300 dark:hover:bg-ink-700'
          }`}
        >
          <Plus className="h-3 w-3" />
          Custom Item
        </button>
      </div>

      {/* Custom item form */}
      {showCustom && (
        <div className="mt-2 flex gap-1">
          <input
            type="text"
            value={newItem.name}
            onChange={e => setNewItem({ ...newItem, name: e.target.value })}
            placeholder="Item name"
            className="flex-1 rounded border border-ink-200 bg-white px-2 py-1 text-sm outline-none focus:border-ink-400 dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:placeholder:text-ink-400"
          />
          <input
            type="number"
            value={newItem.weight}
            onChange={e => setNewItem({ ...newItem, weight: parseFloat(e.target.value) || 0 })}
            placeholder="lb"
            className="w-14 rounded border border-ink-200 bg-white px-2 py-1 text-sm outline-none focus:border-ink-400 dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
            min="0"
            step="0.1"
          />
          <button
            onClick={() => {
              if (newItem.name.trim()) {
                addInventoryItem(character.id, { name: newItem.name.trim(), quantity: newItem.quantity, weight: newItem.weight });
                setNewItem({ name: '', quantity: 1, weight: 0 });
              }
            }}
            className="rounded bg-parchment-100 px-2 py-1 text-ink-600 transition-colors hover:bg-parchment-200 dark:bg-ink-600 dark:text-parchment-200 dark:hover:bg-ink-500"
          >
            <Plus className="h-4 w-4" />
          </button>
        </div>
      )}

      {/* Equipment catalog browser */}
      {showCatalog && (
        <div className="mt-2 rounded-lg border border-ink-100 bg-parchment-50 p-2 dark:border-ink-600 dark:bg-ink-700">
          {/* Search */}
          <div className="relative">
            <Search className="absolute left-2 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-ink-300 dark:text-parchment-400" />
            <input
              type="text"
              value={catalogSearch}
              onChange={e => setCatalogSearch(e.target.value)}
              placeholder="Search equipment..."
              className="w-full rounded border border-ink-200 bg-white py-1.5 pl-7 pr-2 text-sm outline-none focus:border-ink-400 dark:border-ink-500 dark:bg-ink-600 dark:text-parchment-100 dark:focus:border-ink-400"
            />
          </div>

          {/* Categories */}
          <div className="mt-2 max-h-72 space-y-0.5 overflow-y-auto">
            {filteredCatalog.map(cat => {
              const isExpanded = expandedCategory === cat.label || catalogSearch.trim().length > 0;
              return (
                <div key={cat.label}>
                  <button
                    onClick={() => setExpandedCategory(isExpanded && !catalogSearch ? null : cat.label)}
                    className="flex w-full items-center justify-between rounded px-2 py-1.5 text-left text-xs font-semibold uppercase tracking-wider text-ink-500 hover:bg-white dark:text-parchment-300 dark:hover:bg-ink-600"
                  >
                    <span>{cat.label}</span>
                    <div className="flex items-center gap-1">
                      <span className="text-[10px] font-normal normal-case text-ink-400 dark:text-parchment-400">{cat.items.length}</span>
                      {!catalogSearch && (isExpanded ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />)}
                    </div>
                  </button>
                  {isExpanded && (
                    <div className="space-y-0.5 pb-1">
                      {cat.items.map(item => (
                        <div
                          key={item.name}
                          className="flex items-center gap-2 rounded px-2 py-1 text-sm hover:bg-white dark:hover:bg-ink-600"
                        >
                          <div className="min-w-0 flex-1">
                            <div className="font-medium text-ink-700 dark:text-parchment-100">{item.name}</div>
                            {item.detail && (
                              <div className="text-xs text-ink-400 dark:text-parchment-400">{item.detail}</div>
                            )}
                            <div className="text-[10px] text-ink-300 dark:text-ink-400">
                              {item.cost} &middot; {item.weight} lb
                            </div>
                          </div>
                          <button
                            onClick={() => {
                              addInventoryItem(character.id, {
                                name: item.name,
                                quantity: 1,
                                weight: item.weight,
                                description: item.detail,
                              });
                            }}
                            className="shrink-0 rounded bg-royal-blue/10 p-1 text-royal-blue hover:bg-royal-blue/20 dark:bg-royal-light/20 dark:text-royal-light dark:hover:bg-royal-light/30"
                            title="Add to inventory"
                          >
                            <Plus className="h-3 w-3" />
                          </button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
            {filteredCatalog.length === 0 && (
              <p className="py-2 text-center text-xs text-ink-400 dark:text-parchment-400">No matching equipment</p>
            )}
          </div>
        </div>
      )}

      {/* Variant Picker Modal */}
      {variantPicker && (
        <VariantPickerModal
          item={variantPicker}
          onConfirm={(finalName, finalRarity, extraDesc) => {
            addInventoryItem(character.id, {
              name: finalName,
              quantity: 1,
              weight: variantPicker.weight ?? 0,
              description: `${finalRarity} ${variantPicker.type}${variantPicker.subtype ? ` (${variantPicker.subtype})` : ''}${variantPicker.attunement ? ' (requires attunement)' : ''}${variantPicker.cursed ? ' [CURSED]' : ''}\n${extraDesc || variantPicker.description}`,
            });
            setVariantPicker(null);
          }}
          onClose={() => setVariantPicker(null)}
        />
      )}

      {/* Magic Items browser */}
      {showMagic && (
        <MagicItemBrowser
          magicSearch={magicSearch}
          setMagicSearch={setMagicSearch}
          magicRarityFilter={magicRarityFilter}
          setMagicRarityFilter={setMagicRarityFilter}
          magicTypeFilter={magicTypeFilter}
          setMagicTypeFilter={setMagicTypeFilter}
          expandedMagicItem={expandedMagicItem}
          setExpandedMagicItem={setExpandedMagicItem}
          onAdd={(item) => {
            if (item.variants && item.variants.length > 0) {
              setVariantPicker(item);
            } else {
              const CHARGE_ITEMS: Record<string, number> = {
                'ring of spell storing': 5,
                'ring of the ram': 3,
                'ring of evasion': 3,
                'necklace of prayer beads': 6,
                'rod of absorption': 50,
                'rod of resurrection': 5,
                'staff of power': 20,
                'staff of striking': 10,
                'staff of the magi': 50,
                'staff of the woodlands': 10,
                'staff of withering': 3,
                'staff of charming': 10,
                'staff of fire': 10,
                'staff of frost': 10,
                'staff of healing': 10,
                'staff of swarming insects': 10,
                'wand of binding': 7,
                'wand of enemy detection': 7,
                'wand of fear': 7,
                'wand of web': 7,
                'wand of wonder': 7,
                'hammer of thunderbolts': 5,
                'luck blade': 3,
                'mace of terror': 3,
                'nine lives stealer': 9,
                'trident of fish command': 3,
                'cube of force': 36,
                'cubic gate': 3,
                'eyes of charming': 3,
                'gem of brightness': 50,
                'gem of seeing': 3,
                'helm of brilliance': 10,
                'helm of teleportation': 3,
                'medallion of thoughts': 3,
                'pipes of haunting': 3,
                'pipes of the sewers': 3,
                'robe of scintillating colors': 3,
                'scarab of protection': 12,
                'talisman of pure good': 7,
                'talisman of ultimate evil': 6,
              };
              const chargesMax = CHARGE_ITEMS[item.name.toLowerCase()] ?? undefined;
              addInventoryItem(character.id, {
                name: item.name,
                quantity: 1,
                weight: item.weight ?? 0,
                description: `${item.rarity} ${item.type}${item.subtype ? ` (${item.subtype})` : ''}${item.attunement ? ' (requires attunement)' : ''}${item.cursed ? ' [CURSED]' : ''}\n${item.description}`,
                ...(chargesMax ? { charges: 0, chargesMax, chargeNote: '' } : {}),
              });
            }
          }}
        />
      )}
    </div>
  );
}

const RARITY_COLORS: Record<string, string> = {
  common: 'text-ink-500 dark:text-parchment-300',
  uncommon: 'text-emerald-dark dark:text-emerald-light',
  rare: 'text-royal-blue dark:text-royal-light',
  'very rare': 'text-purple-600 dark:text-purple-400',
  legendary: 'text-gold dark:text-gold-light',
  artifact: 'text-crimson dark:text-crimson-light',
};

const RARITY_ORDER = ['common', 'uncommon', 'rare', 'very rare', 'legendary', 'artifact'];

function MagicItemBrowser({
  magicSearch, setMagicSearch,
  magicRarityFilter, setMagicRarityFilter,
  magicTypeFilter, setMagicTypeFilter,
  expandedMagicItem, setExpandedMagicItem,
  onAdd,
}: {
  magicSearch: string;
  setMagicSearch: (s: string) => void;
  magicRarityFilter: string | null;
  setMagicRarityFilter: (s: string | null) => void;
  magicTypeFilter: string | null;
  setMagicTypeFilter: (s: string | null) => void;
  expandedMagicItem: string | null;
  setExpandedMagicItem: (s: string | null) => void;
  onAdd: (item: MagicItem) => void;
}) {
  const types = [...new Set(magicItems.map(i => i.type))].sort();
  const [subFilter, setSubFilter] = useState<string | null>(null);

  const WONDROUS_GROUPS = ['Boots', 'Cloak', 'Robe', 'Bag', 'Helm', 'Belt', 'Amulet', 'Gloves', 'Bracers', 'Necklace', 'Manual', 'Tome'];

  const filtered = magicItems.filter(item => {
    if (magicRarityFilter && item.rarity !== magicRarityFilter) return false;
    if (magicTypeFilter && item.type !== magicTypeFilter) return false;
    if (subFilter && !item.name.toLowerCase().startsWith(subFilter.toLowerCase())) return false;
    if (magicSearch.trim()) {
      const q = magicSearch.toLowerCase();
      return item.name.toLowerCase().includes(q) || item.description.toLowerCase().includes(q);
    }
    return true;
  }).sort((a, b) => {
    // Variant items (generic +1/+2/+3) float to top
    const aVar = a.variants ? 0 : 1;
    const bVar = b.variants ? 0 : 1;
    if (aVar !== bVar) return aVar - bVar;
    return a.name.localeCompare(b.name);
  });

  return (
    <div className="mt-2 rounded-lg border border-gold/20 bg-gold/5 p-2 dark:border-gold-light/20 dark:bg-gold-light/5">
      {/* Search */}
      <div className="relative">
        <Search className="absolute left-2 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-gold dark:text-gold-light" />
        <input
          type="text"
          value={magicSearch}
          onChange={e => setMagicSearch(e.target.value)}
          placeholder="Search magic items..."
          className="w-full rounded border border-gold/30 bg-white py-1.5 pl-7 pr-2 text-sm outline-none focus:border-gold dark:border-gold-light/30 dark:bg-ink-600 dark:text-parchment-100 dark:focus:border-gold-light"
        />
      </div>

      {/* Filters */}
      <div className="mt-2 flex flex-wrap gap-1">
        {/* Rarity cycle button */}
        <button
          onClick={() => {
            const idx = magicRarityFilter ? RARITY_ORDER.indexOf(magicRarityFilter) : -1;
            const next = idx + 1 >= RARITY_ORDER.length ? null : RARITY_ORDER[idx + 1];
            setMagicRarityFilter(next);
          }}
          className={`rounded-full px-2 py-0.5 text-[10px] font-medium capitalize transition-colors ${
            magicRarityFilter
              ? `bg-gold/20 ring-1 ring-gold/30 dark:bg-gold-light/20 dark:ring-gold-light/30 ${RARITY_COLORS[magicRarityFilter] ?? ''}`
              : 'text-ink-400 hover:text-ink-600 dark:text-parchment-400 dark:hover:text-parchment-200'
          }`}
          title="Cycle rarity filter"
        >
          {magicRarityFilter ?? 'All Rarities'}
        </button>
        <span className="mx-0.5 text-ink-200 dark:text-ink-500">|</span>
        {/* Type pills */}
        {types.map(t => (
          <button
            key={t}
            onClick={() => { setMagicTypeFilter(magicTypeFilter === t ? null : t); setSubFilter(null); }}
            className={`rounded-full px-2 py-0.5 text-[10px] font-medium transition-colors ${
              magicTypeFilter === t
                ? 'bg-gold/20 text-gold ring-1 ring-gold/30 dark:bg-gold-light/20 dark:text-gold-light dark:ring-gold-light/30'
                : 'text-ink-400 hover:text-ink-600 dark:text-parchment-400 dark:hover:text-parchment-200'
            }`}
          >
            {t}
          </button>
        ))}
        {/* Wondrous sub-group pills */}
        {magicTypeFilter === 'Wondrous Item' && (
          <>
            <span className="mx-0.5 text-ink-200 dark:text-ink-500">|</span>
            {WONDROUS_GROUPS.map(g => (
              <button
                key={g}
                onClick={() => setSubFilter(subFilter === g ? null : g)}
                className={`rounded-full px-2 py-0.5 text-[10px] font-medium transition-colors ${
                  subFilter === g
                    ? 'bg-gold/20 text-gold ring-1 ring-gold/30 dark:bg-gold-light/20 dark:text-gold-light dark:ring-gold-light/30'
                    : 'text-ink-400 hover:text-ink-600 dark:text-parchment-400 dark:hover:text-parchment-200'
                }`}
              >
                {g}
              </button>
            ))}
          </>
        )}
      </div>

      {/* Legend + Results */}
      <div className="mt-2 flex flex-wrap gap-x-3 gap-y-0 px-2 text-[9px] text-ink-300 dark:text-ink-400">
        <span><Sparkles className="inline h-2.5 w-2.5 text-emerald-dark" /> color = rarity</span>
        <span><span className="text-gold">✦</span> attunement</span>
        <span><span className="text-crimson">☠</span> cursed</span>
        <span><span className="text-gold">▼</span> pick variant</span>
      </div>
      <div className="mt-1 max-h-72 space-y-0.5 overflow-y-auto">
        {filtered.map(item => (
          <div key={item.name} className="rounded px-2 py-1 hover:bg-white dark:hover:bg-ink-600">
            <div className="flex items-center gap-2">
              <button
                onClick={() => setExpandedMagicItem(expandedMagicItem === item.name ? null : item.name)}
                className="flex min-w-0 flex-1 items-center gap-1.5 text-left"
              >
                <Sparkles className={`h-3 w-3 shrink-0 ${RARITY_COLORS[item.rarity] ?? ''}`} />
                <span className="text-sm font-medium text-ink-700 dark:text-parchment-100">{item.name}</span>
                {item.attunement && <span className="shrink-0 text-[10px] text-gold dark:text-gold-light">✦</span>}
                {item.cursed && <span className="shrink-0 text-[10px] text-crimson dark:text-crimson-light">☠</span>}
                {item.variants && <span className="shrink-0 text-[10px] text-gold dark:text-gold-light">▼</span>}
              </button>
              <button
                onClick={() => onAdd(item)}
                className="shrink-0 rounded bg-gold/10 p-1 text-gold hover:bg-gold/20 dark:bg-gold-light/20 dark:text-gold-light dark:hover:bg-gold-light/30"
                title="Add to inventory"
              >
                <Plus className="h-3 w-3" />
              </button>
            </div>
            {expandedMagicItem === item.name && (
              <div className="ml-5 mt-1 mb-1 rounded border border-gold/20 bg-parchment-50 p-2 text-xs leading-relaxed dark:border-gold-light/20 dark:bg-ink-700">
                <div className="mb-1 flex flex-wrap gap-x-3 gap-y-0.5 text-[10px]">
                  <span className={`capitalize font-semibold ${RARITY_COLORS[item.rarity] ?? ''}`}>{item.rarity}</span>
                  <span className="text-ink-400 dark:text-parchment-400">{item.type}{item.subtype ? ` (${item.subtype})` : ''}</span>
                  {item.attunement && <span className="text-gold dark:text-gold-light">{typeof item.attunement === 'string' ? `Attunement: ${item.attunement}` : 'Requires attunement'}</span>}
                  {item.cursed && <span className="font-semibold text-crimson dark:text-crimson-light">Cursed</span>}
                </div>
                <div className="text-ink-600 whitespace-pre-line dark:text-parchment-200">
                  {item.description}
                </div>
              </div>
            )}
          </div>
        ))}
        {filtered.length === 0 && (
          <p className="py-2 text-center text-xs text-ink-400 dark:text-parchment-400">No matching magic items</p>
        )}
        <p className="pt-1 text-center text-[10px] text-ink-300 dark:text-ink-400">{filtered.length} item{filtered.length !== 1 ? 's' : ''}</p>
      </div>
    </div>
  );
}

function VariantPickerModal({ item, onConfirm, onClose }: {
  item: MagicItem;
  onConfirm: (name: string, rarity: string, extraDesc: string) => void;
  onClose: () => void;
}) {
  const [selections, setSelections] = useState<Record<number, number>>({});

  const allSelected = (item.variants ?? []).every((_, i) => selections[i] !== undefined);

  // Build final name, rarity, and description from selections
  function getResult() {
    let name = item.name;
    let rarity = item.rarity;
    let extraDesc = '';
    const variants = item.variants ?? [];

    // Detect generic names like "Weapon, +1, +2, or +3" or "Ammunition, +1, +2, or +3"
    // where the first dropdown replaces the base name entirely
    const GENERIC_BASES = ['Weapon', 'Armor', 'Ammunition'];
    const basePart = name.split(',')[0].trim();
    const isGenericName = GENERIC_BASES.includes(basePart) && variants.length > 1;

    if (isGenericName) {
      // First dropdown = base name (e.g. "Longsword"), rest = suffixes (e.g. " +1")
      const firstOpt = variants[0]?.options[selections[0] ?? 0];
      name = firstOpt?.name ?? name;
      for (let i = 1; i < variants.length; i++) {
        const opt = variants[i]?.options[selections[i] ?? 0];
        if (opt?.suffix) name += opt.suffix;
        if (opt?.rarity) rarity = opt.rarity;
        if (opt?.description) extraDesc = opt.description;
      }
    } else {
      // Named item: keep base name, append all suffixes
      // Strip generic suffix patterns from the base name first
      name = name.replace(/,\s*\+1.*$/i, '');
      for (let i = 0; i < variants.length; i++) {
        const opt = variants[i]?.options[selections[i] ?? 0];
        if (opt?.suffix) name += opt.suffix;
        if (opt?.rarity) rarity = opt.rarity;
        if (opt?.description) extraDesc = opt.description;
      }
    }

    return { name, rarity, extraDesc };
  }

  const result = allSelected ? getResult() : null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="mx-4 w-full max-w-md rounded-xl border border-gold/30 bg-white p-5 shadow-xl dark:border-gold-light/30 dark:bg-ink-800">
        <div className="flex items-center justify-between">
          <h3 className="flex items-center gap-2 text-sm font-bold text-ink-800 dark:text-parchment-100">
            <Sparkles className="h-4 w-4 text-gold dark:text-gold-light" />
            {item.name}
          </h3>
          <button onClick={onClose} className="rounded p-1 text-ink-400 hover:text-ink-600 dark:text-parchment-300 dark:hover:text-parchment-100">
            <X className="h-4 w-4" />
          </button>
        </div>

        <p className="mt-2 text-xs text-ink-400 dark:text-parchment-400">Choose the specific variant:</p>

        <div className="mt-3 space-y-3">
          {(item.variants ?? []).map((variant, vi) => (
            <div key={vi}>
              <label className="text-xs font-semibold uppercase tracking-wider text-ink-500 dark:text-parchment-300">{variant.label}</label>
              <select
                value={selections[vi] ?? ''}
                onChange={e => setSelections(s => ({ ...s, [vi]: parseInt(e.target.value) }))}
                className="mt-1 w-full rounded border border-ink-200 bg-white px-2 py-1.5 text-sm outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
              >
                <option value="" disabled>— Select {variant.label} —</option>
                {variant.options.map((opt, oi) => (
                  <option key={oi} value={oi}>
                    {opt.name}{opt.rarity ? ` (${opt.rarity})` : ''}
                  </option>
                ))}
              </select>
            </div>
          ))}
        </div>

        {/* Preview */}
        {result && (
          <div className="mt-4 rounded-lg border border-gold/20 bg-gold/5 p-3 dark:border-gold-light/20 dark:bg-gold-light/5">
            <div className="flex items-center gap-2">
              <Sparkles className={`h-3.5 w-3.5 ${RARITY_COLORS[result.rarity] ?? ''}`} />
              <span className="font-semibold text-sm text-ink-700 dark:text-parchment-100">{result.name}</span>
              <span className={`text-[10px] capitalize ${RARITY_COLORS[result.rarity] ?? ''}`}>{result.rarity}</span>
            </div>
            {result.extraDesc && (
              <p className="mt-1 text-xs text-ink-500 dark:text-parchment-300">{result.extraDesc}</p>
            )}
          </div>
        )}

        <div className="mt-4 flex justify-end gap-2">
          <button
            onClick={onClose}
            className="rounded-lg border border-ink-200 px-4 py-2 text-sm font-medium text-ink-600 hover:bg-parchment-50 dark:border-ink-600 dark:text-parchment-200 dark:hover:bg-ink-700"
          >
            Cancel
          </button>
          <button
            onClick={() => result && onConfirm(result.name, result.rarity, result.extraDesc)}
            disabled={!allSelected}
            className="rounded-lg bg-gold px-4 py-2 text-sm font-medium text-ink-800 hover:bg-gold/90 disabled:opacity-30 dark:bg-gold-light dark:text-ink-800 dark:hover:bg-gold-light/90"
          >
            Add to Inventory
          </button>
        </div>
      </div>
    </div>
  );
}
