import { useState } from 'react';
import { useCharacterStore } from '@/store/characterStore';
import { getRace, getClass, getBackground, xpByLevel } from '@/data';
import type { Character, ComputedStats } from '@/types';
import { Shield, Zap, Footprints, Eye, ArrowUpCircle, Dices, RotateCcw } from 'lucide-react';
import { getClasses, getCharacterLevel } from '@/store/classHelpers';

const DICE = [4, 6, 8, 10, 12, 20, 100] as const;

function DiceTray() {
  const [pool, setPool] = useState<Record<number, number>>({});
  const [modifier, setModifier] = useState(0);
  const [result, setResult] = useState<{ rolls: { die: number; value: number }[]; mod: number; total: number } | null>(null);

  const totalDice = Object.values(pool).reduce((s, n) => s + n, 0);

  function addDie(sides: number) {
    setPool(p => ({ ...p, [sides]: (p[sides] ?? 0) + 1 }));
    setResult(null);
  }

  function removeDie(sides: number) {
    setPool(p => {
      const count = (p[sides] ?? 0) - 1;
      if (count <= 0) { const { [sides]: _, ...rest } = p; return rest; }
      return { ...p, [sides]: count };
    });
    setResult(null);
  }

  function roll() {
    const rolls: { die: number; value: number }[] = [];
    for (const [sides, count] of Object.entries(pool)) {
      const s = Number(sides);
      for (let i = 0; i < count; i++) {
        rolls.push({ die: s, value: Math.floor(Math.random() * s) + 1 });
      }
    }
    const total = rolls.reduce((s, r) => s + r.value, 0) + modifier;
    setResult({ rolls, mod: modifier, total });
  }

  function clear() {
    setPool({});
    setModifier(0);
    setResult(null);
  }

  // Build formula string
  const formula = Object.entries(pool)
    .sort(([a], [b]) => Number(a) - Number(b))
    .map(([sides, count]) => `${count}d${sides}`)
    .join(' + ') || 'Pick dice';
  const fullFormula = formula + (modifier > 0 ? ` + ${modifier}` : modifier < 0 ? ` - ${Math.abs(modifier)}` : '');

  return (
    <div className="flex flex-col items-center gap-1.5">
      {/* Dice buttons */}
      <div className="flex flex-wrap justify-center gap-1">
        {DICE.map(d => {
          const count = pool[d] ?? 0;
          return (
            <button
              key={d}
              onClick={() => addDie(d)}
              onContextMenu={e => { e.preventDefault(); removeDie(d); }}
              className={`relative rounded px-2 py-1 text-xs font-bold transition-colors ${
                count > 0
                  ? 'bg-crimson/10 text-crimson dark:bg-crimson-light/20 dark:text-crimson-light'
                  : 'bg-ink-100/60 text-ink-400 hover:bg-ink-200 hover:text-ink-600 dark:bg-ink-600 dark:text-parchment-400 dark:hover:bg-ink-500 dark:hover:text-parchment-200'
              }`}
              title={`Left-click: add d${d}. Right-click: remove.`}
            >
              d{d}
              {count > 0 && (
                <span className="absolute -right-1 -top-1 flex h-3.5 w-3.5 items-center justify-center rounded-full bg-crimson text-[8px] font-bold text-white dark:bg-crimson-light">
                  {count}
                </span>
              )}
            </button>
          );
        })}
      </div>

      {/* Modifier + roll row */}
      <div className="flex items-center gap-1.5">
        <div className="flex items-center gap-0.5 rounded bg-ink-100/60 px-1 dark:bg-ink-600">
          <button onClick={() => setModifier(m => m - 1)} className="px-1 text-xs font-bold text-ink-400 hover:text-ink-600 dark:text-parchment-400 dark:hover:text-parchment-200">&minus;</button>
          <span className="w-8 text-center text-xs font-semibold text-ink-600 dark:text-parchment-200">{modifier >= 0 ? `+${modifier}` : modifier}</span>
          <button onClick={() => setModifier(m => m + 1)} className="px-1 text-xs font-bold text-ink-400 hover:text-ink-600 dark:text-parchment-400 dark:hover:text-parchment-200">+</button>
        </div>
        <button
          onClick={roll}
          disabled={totalDice === 0}
          className="flex items-center gap-1 rounded bg-crimson px-3 py-1 text-xs font-bold text-white transition-colors hover:bg-crimson/90 disabled:opacity-30 dark:bg-crimson-light dark:hover:bg-crimson-light/90"
        >
          <Dices className="h-3.5 w-3.5" /> Roll
        </button>
        {totalDice > 0 && (
          <button onClick={clear} className="rounded p-1 text-ink-300 hover:text-ink-500 dark:text-ink-400 dark:hover:text-parchment-200" title="Clear">
            <RotateCcw className="h-3.5 w-3.5" />
          </button>
        )}
      </div>

      {/* Formula */}
      <div className="text-[10px] text-ink-300 dark:text-ink-400">{fullFormula}</div>

      {/* Result */}
      {result && (
        <div className="rounded-lg bg-parchment-100 px-3 py-1 text-center dark:bg-ink-700">
          <div className="text-xl font-bold text-ink-800 dark:text-parchment-100">{result.total}</div>
          <div className="text-[10px] text-ink-400 dark:text-parchment-400">
            {result.rolls.map((r, i) => (
              <span key={i}>
                {i > 0 && ' + '}
                <span className={r.value === r.die ? 'font-bold text-gold dark:text-gold-light' : r.value === 1 ? 'font-bold text-crimson dark:text-crimson-light' : ''}>
                  {r.value}
                </span>
                <span className="text-ink-300 dark:text-ink-500">d{r.die}</span>
              </span>
            ))}
            {result.mod !== 0 && <span> {result.mod >= 0 ? '+' : ''}{result.mod}</span>}
          </div>
        </div>
      )}
    </div>
  );
}

interface Props {
  character: Character;
  stats: ComputedStats;
  onLevelUp?: () => void;
}

export function CharacterHeader({ character, stats, onLevelUp }: Props) {
  const updateCharacter = useCharacterStore(s => s.updateCharacter);
  const [showMobileDice, setShowMobileDice] = useState(false);
  const race = getRace(character.raceKey);
  const subrace = race?.subraces?.find(s => s.key === character.subraceKey);
  const cls = getClass(character.classKey);
  const bg = getBackground(character.backgroundKey);
  const charClasses = getClasses(character);
  const totalLevel = getCharacterLevel(character);

  const raceName = subrace ? subrace.name : race?.name ?? character.raceKey;
  const classDisplay = charClasses.map(e => {
    const c = getClass(e.classKey);
    return `${c?.name ?? e.classKey} ${e.classLevel}`;
  }).join(' / ');

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm backdrop-blur-sm dark:border-ink-600 dark:bg-ink-800/80">
      <div className="flex flex-wrap items-start justify-between gap-4">
        <div className="min-w-0 flex-1">
          <input
            type="text"
            value={character.name}
            onChange={e => updateCharacter(character.id, { name: e.target.value })}
            className="w-full border-none bg-transparent text-3xl font-bold text-ink-800 outline-none placeholder:text-ink-300 focus:ring-0 dark:text-parchment-100 dark:placeholder:text-ink-500"
            placeholder="Character Name"
          />
          <div className="mt-1 flex flex-wrap items-center gap-x-4 gap-y-1 text-sm text-ink-400 dark:text-parchment-300">
            <span>{raceName}</span>
            <span className="flex items-center gap-1">
              {classDisplay}
              {totalLevel < 20 && onLevelUp && (
                <button
                  onClick={onLevelUp}
                  className="rounded p-0.5 text-gold hover:text-gold/80 dark:text-gold-light dark:hover:text-gold-light/80"
                  title="Level Up"
                >
                  <ArrowUpCircle className="h-4 w-4" />
                </button>
              )}
            </span>
            {charClasses.map(e => {
              if (!e.subclassKey) return null;
              const c = getClass(e.classKey);
              const sub = c?.subclasses.find(s => s.key === e.subclassKey);
              return sub ? <span key={e.classKey} className="text-ink-300 dark:text-ink-400">({sub.name})</span> : null;
            })}
            <span>{bg?.name ?? character.backgroundKey}</span>
            <span>{character.alignment}</span>
          </div>
        </div>

        {/* Dice Tray — fills empty center space on desktop, stacks on mobile */}
        <div className="hidden flex-1 justify-center lg:flex">
          <DiceTray />
        </div>

        <div className="flex gap-3">
          {[
            { icon: Shield, value: stats.ac, label: 'AC' },
            { icon: Zap, value: `${stats.initiative >= 0 ? '+' : ''}${stats.initiative}`, label: 'Init' },
            { icon: Footprints, value: character.speedOverride ?? character.speed, label: 'Speed' },
            { icon: Eye, value: stats.passivePerception, label: 'P.Per' },
          ].map(({ icon: Icon, value, label }) => (
            <div key={label} className="flex flex-col items-center rounded-lg border-2 border-ink-200 bg-parchment-50 px-3 py-1.5 dark:border-ink-600 dark:bg-ink-700">
              <Icon className="mb-0.5 h-4 w-4 text-ink-400 dark:text-parchment-300" />
              <span className="text-2xl font-bold leading-none text-ink-800 dark:text-parchment-100">{value}</span>
              <span className="text-[10px] font-medium uppercase tracking-wider text-ink-400 dark:text-parchment-400">{label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Mobile dice tray toggle */}
      <div className="mt-3 lg:hidden">
        <button
          onClick={() => setShowMobileDice(d => !d)}
          className="flex w-full items-center justify-center gap-1.5 rounded-lg border border-ink-200/50 bg-parchment-50 py-1.5 text-xs font-semibold text-ink-400 transition-colors hover:text-ink-600 dark:border-ink-600 dark:bg-ink-700 dark:text-parchment-400 dark:hover:text-parchment-200"
        >
          <Dices className="h-3.5 w-3.5" /> {showMobileDice ? 'Hide' : 'Dice Tray'}
        </button>
        {showMobileDice && (
          <div className="mt-2">
            <DiceTray />
          </div>
        )}
      </div>

      <div className="mt-3 flex flex-wrap items-center gap-4 border-t border-ink-100 pt-2 text-sm text-ink-400 dark:border-ink-600 dark:text-parchment-300">
        <span>Prof. Bonus: <strong className="text-ink-700 dark:text-parchment-100">+{stats.proficiencyBonus}</strong></span>
        <div className="flex items-center gap-1">
          <span>XP:</span>
          <input
            type="number"
            value={character.xp}
            onChange={e => updateCharacter(character.id, { xp: parseInt(e.target.value) || 0 })}
            className="w-24 border-none bg-transparent text-center font-semibold text-ink-700 outline-none dark:text-parchment-100"
          />
          {totalLevel < 20 && (() => {
            const currentLevelXp = xpByLevel[String(totalLevel)] ?? 0;
            const nextLevelXp = xpByLevel[String(totalLevel + 1)] ?? 0;
            const xpNeeded = nextLevelXp - character.xp;
            const progress = nextLevelXp > currentLevelXp
              ? Math.min(100, Math.max(0, ((character.xp - currentLevelXp) / (nextLevelXp - currentLevelXp)) * 100))
              : 0;
            return (
              <span className="flex items-center gap-1.5">
                <span className="text-xs text-ink-300 dark:text-ink-400">/ {nextLevelXp.toLocaleString()}</span>
                <div className="h-1.5 w-16 overflow-hidden rounded-full bg-ink-100 dark:bg-ink-600">
                  <div
                    className="h-full rounded-full bg-gold transition-all duration-300 dark:bg-gold-light"
                    style={{ width: `${progress}%` }}
                  />
                </div>
                {xpNeeded > 0 ? (
                  <span className="text-[10px] text-ink-300 dark:text-ink-400">{xpNeeded.toLocaleString()} to lvl {totalLevel + 1}</span>
                ) : (
                  <span className="text-[10px] font-semibold text-gold dark:text-gold-light">Level up available!</span>
                )}
              </span>
            );
          })()}
        </div>
        {stats.spellSaveDC !== null && (
          <>
            <span>Spell Save DC: <strong className="text-ink-700 dark:text-parchment-100">{stats.spellSaveDC}</strong></span>
            <span>Spell Attack: <strong className="text-ink-700 dark:text-parchment-100">+{stats.spellAttackBonus}</strong></span>
          </>
        )}
      </div>
    </div>
  );
}
