import { useCharacterStore } from '@/store/characterStore';
import type { Character } from '@/types';
import { Moon, Sun } from 'lucide-react';

interface Props {
  character: Character;
}

export function RestButtons({ character }: Props) {
  const { shortRest, longRest } = useCharacterStore();

  return (
    <div className="flex gap-2">
      <button
        onClick={() => shortRest(character.id)}
        className="flex flex-1 items-center justify-center gap-2 rounded-lg border border-ink-200 bg-white px-4 py-2.5 text-sm font-medium text-ink-600 shadow-sm transition-colors hover:bg-parchment-50 dark:border-ink-600 dark:bg-ink-800 dark:text-parchment-200 dark:hover:bg-ink-700"
      >
        <Sun className="h-4 w-4" />
        Short Rest
      </button>
      <button
        onClick={() => longRest(character.id)}
        className="flex flex-1 items-center justify-center gap-2 rounded-lg border border-royal-blue/30 bg-royal-blue/5 px-4 py-2.5 text-sm font-medium text-royal-blue shadow-sm transition-colors hover:bg-royal-blue/10 dark:border-royal-light/30 dark:bg-royal-light/10 dark:text-royal-light dark:hover:bg-royal-light/20"
      >
        <Moon className="h-4 w-4" />
        Long Rest
      </button>
    </div>
  );
}
