import { useCharacterStore } from '@/store/characterStore';
import type { Character } from '@/types';
import { Sparkles } from 'lucide-react';

interface Props {
  character: Character;
}

export function SpellSlots({ character }: Props) {
  const { useSpellSlot, restoreSpellSlot } = useCharacterStore();
  const levels = Object.keys(character.spellSlots)
    .map(Number)
    .filter(l => character.spellSlots[l]?.max > 0)
    .sort((a, b) => a - b);

  if (levels.length === 0) return null;

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-2 flex items-center gap-1.5 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">
        <Sparkles className="h-3.5 w-3.5" /> Spell Slots
      </h3>
      <div className="space-y-2">
        {levels.map(level => {
          const slot = character.spellSlots[level];
          return (
            <div key={level} className="flex items-center gap-2">
              <span className="w-12 text-xs font-semibold text-ink-500 dark:text-parchment-300">
                {level === 0 ? 'Cantrip' : `${level}${level === 1 ? 'st' : level === 2 ? 'nd' : level === 3 ? 'rd' : 'th'}`}
              </span>
              <div className="flex gap-1">
                {Array.from({ length: slot.max }, (_, i) => (
                  <button
                    key={i}
                    onClick={() =>
                      i < slot.current
                        ? useSpellSlot(character.id, level)
                        : restoreSpellSlot(character.id, level)
                    }
                    className={`h-5 w-5 rounded transition-colors ${
                      i < slot.current
                        ? 'bg-royal-blue shadow-sm dark:bg-royal-light'
                        : 'border border-ink-200 bg-white hover:border-ink-300 dark:border-ink-500 dark:bg-ink-700'
                    }`}
                  />
                ))}
              </div>
              <span className="text-xs text-ink-400 dark:text-parchment-400">{slot.current}/{slot.max}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
