import { useState } from 'react';
import { useCharacterStore, getDefaultSpellSlots, computeStats } from '@/store/characterStore';
import { getClass, getSpellLimits, classes as allClasses } from '@/data';
import type { Character } from '@/types';
import { X, Sparkles, Swords, Shield, BookOpen, Star, Plus, ChevronUp } from 'lucide-react';
import { getClasses, getCharacterLevel, meetsMulticlassPrereqs, getMulticlassProficiencies } from '@/store/classHelpers';

interface Props {
  character: Character;
  onClose: () => void;
}

interface LevelChoice {
  type: 'subclass' | 'asi' | 'fighting_style' | 'info';
  level: number;
  name: string;
  description: string;
  options?: { key: string; name: string; description?: string }[];
}

function getLevelChoicesForClass(classKey: string, newClassLevel: number, subclassKey: string | null): LevelChoice[] {
  const cls = getClass(classKey);
  if (!cls) return [];

  const choices: LevelChoice[] = [];

  // Subclass selection
  if (cls.subclassLevel && newClassLevel >= cls.subclassLevel && !subclassKey) {
    choices.push({
      type: 'subclass',
      level: cls.subclassLevel,
      name: cls.subclasses[0]?.flavor ?? 'Subclass',
      description: `Choose your ${cls.subclasses[0]?.flavor ?? 'subclass'}.`,
      options: cls.subclasses.map(s => ({
        key: s.key,
        name: s.name,
        description: s.description,
      })),
    });
  }

  // ASI at standard levels (per-class level, not total)
  const asiLevels = [4, 8, 12, 16, 19];
  if (cls.key === 'fighter') asiLevels.push(6, 14);
  if (cls.key === 'rogue') asiLevels.push(10);
  asiLevels.sort((a, b) => a - b);

  if (asiLevels.includes(newClassLevel)) {
    choices.push({
      type: 'asi',
      level: newClassLevel,
      name: 'Ability Score Improvement',
      description: 'Increase one ability score by 2, or two ability scores by 1 each (max 20). Or choose a feat if your DM allows it.',
    });
  }

  // Fighting style
  for (const [lvlStr, feats] of Object.entries(cls.features)) {
    const lvl = Number(lvlStr);
    if (lvl !== newClassLevel) continue;
    for (const f of feats) {
      if (f.name === 'Fighting Style') {
        choices.push({
          type: 'fighting_style',
          level: lvl,
          name: 'Fighting Style',
          description: f.description,
        });
      }
    }
  }

  // Spell reminders
  if (cls.spellcasting) {
    const limits = getSpellLimits(classKey, newClassLevel, subclassKey);
    const prevLimits = newClassLevel > 1 ? getSpellLimits(classKey, newClassLevel - 1, subclassKey) : { cantripsKnown: 0, spellsKnown: 0 };

    const newCantrips = (limits.cantripsKnown ?? 0) - (prevLimits.cantripsKnown ?? 0);
    const newSpells = (limits.spellsKnown ?? 0) - (prevLimits.spellsKnown ?? 0);

    if (newCantrips > 0 || newSpells > 0) {
      const parts: string[] = [];
      if (newCantrips > 0) parts.push(`${newCantrips} new cantrip${newCantrips > 1 ? 's' : ''}`);
      if (newSpells > 0) parts.push(`${newSpells} new spell${newSpells > 1 ? 's' : ''}`);
      choices.push({
        type: 'info',
        level: newClassLevel,
        name: 'New Spells Available',
        description: `You can learn ${parts.join(' and ')}. Update your spell list in the Spells section.`,
      });
    }

    const slots = getDefaultSpellSlots(classKey, newClassLevel, subclassKey);
    const prevSlots = newClassLevel > 1 ? getDefaultSpellSlots(classKey, newClassLevel - 1, subclassKey) : {};
    const newSlotLevels = Object.keys(slots)
      .map(Number)
      .filter(l => !prevSlots[l] && slots[l]?.max > 0);
    if (newSlotLevels.length > 0) {
      choices.push({
        type: 'info',
        level: newClassLevel,
        name: 'New Spell Slot Level',
        description: `You now have level ${newSlotLevels.join(', ')} spell slots!`,
      });
    }
  }

  // First level in a new class via multiclass: show proficiency gains
  if (newClassLevel === 1) {
    const profs = getMulticlassProficiencies(classKey);
    const parts: string[] = [];
    if (profs.armor.length) parts.push(`Armor: ${profs.armor.join(', ')}`);
    if (profs.weapons.length) parts.push(`Weapons: ${profs.weapons.join(', ')}`);
    if (profs.tools.length) parts.push(`Tools: ${profs.tools.join(', ')}`);
    if (profs.skills > 0) parts.push(`${profs.skills} skill${profs.skills > 1 ? 's' : ''} of your choice`);
    if (parts.length > 0) {
      choices.unshift({
        type: 'info',
        level: 1,
        name: 'Multiclass Proficiencies',
        description: `You gain: ${parts.join('. ')}.`,
      });
    }
  }

  return choices;
}

function ChoiceIcon({ type }: { type: LevelChoice['type'] }) {
  switch (type) {
    case 'subclass': return <Shield className="h-4 w-4" />;
    case 'asi': return <ChevronUp className="h-4 w-4" />;
    case 'fighting_style': return <Swords className="h-4 w-4" />;
    case 'info': return <BookOpen className="h-4 w-4" />;
  }
}

export function LevelUpModal({ character, onClose }: Props) {
  const { updateCharacter, levelUpClass } = useCharacterStore();
  const classes = getClasses(character);
  const totalLevel = getCharacterLevel(character);
  const stats = computeStats(character);

  // Selected class to level up in (default: primary class)
  const [selectedClassKey, setSelectedClassKey] = useState<string>(classes[0].classKey);
  const [showNewClass, setShowNewClass] = useState(false);
  const [newSubclassKey, setNewSubclassKey] = useState<string | null>(null);

  const isNewClass = !classes.some(e => e.classKey === selectedClassKey);
  const currentEntry = classes.find(e => e.classKey === selectedClassKey);
  const newClassLevel = isNewClass ? 1 : (currentEntry?.classLevel ?? 0) + 1;
  const selectedCls = getClass(selectedClassKey);

  const choices = getLevelChoicesForClass(
    selectedClassKey,
    newClassLevel,
    isNewClass ? newSubclassKey : (currentEntry?.subclassKey ?? null)
  );

  // Classes available for multiclassing
  const existingClassKeys = new Set(classes.map(e => e.classKey));
  const availableNewClasses = allClasses.filter(c => !existingClassKeys.has(c.key));

  function applyLevelUp() {
    // For subclass selection on existing class, update it first
    if (!isNewClass && newSubclassKey && currentEntry && !currentEntry.subclassKey) {
      const updatedClasses = classes.map(e =>
        e.classKey === selectedClassKey ? { ...e, subclassKey: newSubclassKey } : e
      );
      updateCharacter(character.id, { classes: updatedClasses, subclassKey: classes[0].classKey === selectedClassKey ? newSubclassKey : character.subclassKey });
    }

    levelUpClass(character.id, selectedClassKey, isNewClass ? newSubclassKey : undefined);
    onClose();
  }

  if (totalLevel >= 20) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
        <div className="mx-4 w-full max-w-lg rounded-xl border border-ink-200 bg-white p-6 shadow-xl dark:border-ink-600 dark:bg-ink-800">
          <p className="text-center text-ink-500 dark:text-parchment-300">Maximum level (20) reached.</p>
          <button onClick={onClose} className="mt-4 w-full rounded-lg border border-ink-200 px-4 py-2 text-sm dark:border-ink-600 dark:text-parchment-200">Close</button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="mx-4 w-full max-w-lg rounded-xl border border-ink-200 bg-white p-6 shadow-xl dark:border-ink-600 dark:bg-ink-800">
        <div className="flex items-center justify-between">
          <h2 className="flex items-center gap-2 text-lg font-bold text-ink-800 dark:text-parchment-100">
            <Sparkles className="h-5 w-5 text-gold dark:text-gold-light" />
            Level Up
          </h2>
          <button onClick={onClose} className="rounded p-1 text-ink-400 hover:text-ink-600 dark:text-parchment-300 dark:hover:text-parchment-100">
            <X className="h-5 w-5" />
          </button>
        </div>

        {/* Current class summary */}
        <div className="mt-2 text-sm text-ink-500 dark:text-parchment-300">
          {classes.map(e => {
            const c = getClass(e.classKey);
            return `${c?.name ?? e.classKey} ${e.classLevel}`;
          }).join(' / ')} (Total Level {totalLevel})
        </div>

        {/* Class selector */}
        <div className="mt-3">
          <label className="text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">Level up in:</label>
          <div className="mt-1 flex flex-wrap gap-1.5">
            {classes.map(entry => {
              const c = getClass(entry.classKey);
              const isSelected = selectedClassKey === entry.classKey && !showNewClass;
              return (
                <button
                  key={entry.classKey}
                  onClick={() => { setSelectedClassKey(entry.classKey); setShowNewClass(false); setNewSubclassKey(null); }}
                  className={`rounded-lg border-2 px-3 py-1.5 text-sm font-medium transition-colors ${
                    isSelected
                      ? 'border-crimson bg-crimson/5 text-crimson dark:border-crimson-light dark:bg-crimson-light/10 dark:text-crimson-light'
                      : 'border-ink-200 text-ink-600 hover:border-ink-300 dark:border-ink-600 dark:text-parchment-300 dark:hover:border-ink-500'
                  }`}
                >
                  {c?.name ?? entry.classKey} {entry.classLevel} → {entry.classLevel + 1}
                </button>
              );
            })}
            {availableNewClasses.length > 0 && (
              <button
                onClick={() => { setShowNewClass(true); setNewSubclassKey(null); }}
                className={`flex items-center gap-1 rounded-lg border-2 px-3 py-1.5 text-sm font-medium transition-colors ${
                  showNewClass
                    ? 'border-gold bg-gold/5 text-gold dark:border-gold-light dark:bg-gold-light/10 dark:text-gold-light'
                    : 'border-ink-200 text-ink-400 hover:border-ink-300 dark:border-ink-600 dark:text-parchment-400 dark:hover:border-ink-500'
                }`}
              >
                <Plus className="h-3.5 w-3.5" /> Multiclass
              </button>
            )}
          </div>
        </div>

        {/* New class picker */}
        {showNewClass && (
          <div className="mt-3 rounded-lg border border-gold/30 bg-gold/5 p-3 dark:border-gold-light/30 dark:bg-gold-light/5">
            <label className="text-xs font-semibold uppercase tracking-wider text-gold dark:text-gold-light">Choose new class:</label>
            <div className="mt-2 grid grid-cols-2 gap-1.5 sm:grid-cols-3">
              {availableNewClasses.map(c => {
                const prereq = meetsMulticlassPrereqs(character, c.key, stats.abilityTotals);
                const isSelected = selectedClassKey === c.key && showNewClass;
                return (
                  <button
                    key={c.key}
                    onClick={() => prereq.met && setSelectedClassKey(c.key)}
                    disabled={!prereq.met}
                    title={prereq.met ? '' : prereq.reason}
                    className={`rounded border-2 px-2 py-1.5 text-left text-xs transition-colors ${
                      isSelected
                        ? 'border-gold bg-gold/10 text-gold dark:border-gold-light dark:bg-gold-light/10 dark:text-gold-light'
                        : prereq.met
                        ? 'border-ink-200 text-ink-600 hover:border-ink-300 dark:border-ink-600 dark:text-parchment-300 dark:hover:border-ink-500'
                        : 'border-ink-100 text-ink-300 opacity-50 dark:border-ink-700 dark:text-ink-500'
                    }`}
                  >
                    <div className="font-medium">{c.name}</div>
                    {!prereq.met && (
                      <div className="mt-0.5 text-[9px] text-crimson dark:text-crimson-light">{prereq.reason.split('.')[0]}</div>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* What you get at this level */}
        {selectedCls && (
          <div className="mt-3 text-sm text-ink-500 dark:text-parchment-300">
            <span className="text-ink-300 dark:text-ink-400">{selectedCls.name}</span>
            {' → '}
            <span className="font-bold text-crimson dark:text-crimson-light">Level {newClassLevel}</span>
            <span className="ml-2 text-xs text-ink-300 dark:text-ink-400">(d{selectedCls.hitDie} hit die)</span>
          </div>
        )}

        {/* Choices */}
        <div className="mt-3 max-h-60 space-y-2 overflow-y-auto">
          {choices.length === 0 && (
            <p className="text-sm text-ink-400 dark:text-parchment-400">No special choices at this level — just apply the level up!</p>
          )}

          {choices.map((choice, i) => (
            <div key={`${choice.type}-${choice.level}-${i}`} className="rounded-lg border border-ink-100 p-3 dark:border-ink-600">
              <div className="flex items-center gap-2">
                <span className={`${choice.type === 'info' ? 'text-royal-blue dark:text-royal-light' : 'text-gold dark:text-gold-light'}`}>
                  <ChoiceIcon type={choice.type} />
                </span>
                <h4 className="text-sm font-semibold text-ink-700 dark:text-parchment-100">{choice.name}</h4>
              </div>
              <p className="mt-1 text-xs text-ink-500 dark:text-parchment-300">{choice.description}</p>

              {/* Subclass options */}
              {choice.type === 'subclass' && choice.options && (
                <div className="mt-2 space-y-1">
                  {choice.options.map(opt => (
                    <button
                      key={opt.key}
                      onClick={() => {
                        if (isNewClass) {
                          setNewSubclassKey(opt.key);
                        } else {
                          updateCharacter(character.id, { subclassKey: opt.key });
                        }
                      }}
                      className={`w-full rounded border-2 p-2 text-left text-sm transition-colors ${
                        (isNewClass ? newSubclassKey : character.subclassKey) === opt.key
                          ? 'border-crimson bg-crimson/5 dark:border-crimson-light dark:bg-crimson-light/10'
                          : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                      }`}
                    >
                      <span className="font-medium text-ink-700 dark:text-parchment-100">{opt.name}</span>
                      {opt.description && (
                        <p className="mt-0.5 text-xs text-ink-400 dark:text-parchment-400">{opt.description?.slice(0, 150)}...</p>
                      )}
                    </button>
                  ))}
                </div>
              )}

              {/* ASI */}
              {choice.type === 'asi' && (
                <div className="mt-2 flex items-center gap-2 rounded bg-gold/5 p-2 dark:bg-gold-light/10">
                  <Star className="h-4 w-4 text-gold dark:text-gold-light shrink-0" />
                  <p className="text-xs text-ink-500 dark:text-parchment-300">
                    You'll gain a <strong className="text-gold dark:text-gold-light">Feat/ASI slot</strong> — choose a feat or increase ability scores from the <strong>Feats</strong> section after leveling up.
                  </p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Apply */}
        <div className="mt-4 flex justify-end gap-2">
          <button
            onClick={onClose}
            className="rounded-lg border border-ink-200 px-4 py-2 text-sm font-medium text-ink-600 hover:bg-parchment-50 dark:border-ink-600 dark:text-parchment-200 dark:hover:bg-ink-700"
          >
            Cancel
          </button>
          <button
            onClick={applyLevelUp}
            className="rounded-lg bg-crimson px-6 py-2 text-sm font-medium text-white hover:bg-crimson/90 dark:bg-crimson-light dark:hover:bg-crimson-light/90"
          >
            {isNewClass ? `Multiclass into ${selectedCls?.name}` : `Level ${selectedCls?.name} to ${newClassLevel}`}
          </button>
        </div>
      </div>
    </div>
  );
}
