import { useCharacterStore } from '@/store/characterStore';
import type { Character } from '@/types';
import { Dices } from 'lucide-react';
import { getHitDiceByClass } from '@/store/classHelpers';

interface Props {
  character: Character;
}

export function HitDice({ character }: Props) {
  const { useHitDie } = useCharacterStore();
  const pools = getHitDiceByClass(character);

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-2 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">Hit Dice</h3>
      <div className="space-y-2">
        {pools.map(pool => (
          <div key={pool.classKey} className="flex items-center gap-3">
            <Dices className="h-5 w-5 text-ink-400 dark:text-parchment-300" />
            <span className="text-lg font-bold text-ink-700 dark:text-parchment-100">{pool.current}d{pool.dieType}</span>
            <span className="text-sm text-ink-400 dark:text-parchment-400">/ {pool.max}d{pool.dieType}</span>
            {pools.length > 1 && (
              <span className="text-[10px] text-ink-300 dark:text-ink-400">{pool.className}</span>
            )}
            <button
              onClick={() => useHitDie(character.id, pool.classKey)}
              disabled={pool.current <= 0}
              className="ml-auto rounded bg-parchment-100 px-3 py-1 text-sm font-medium text-ink-600 transition-colors hover:bg-parchment-200 disabled:opacity-40 dark:bg-ink-600 dark:text-parchment-200 dark:hover:bg-ink-500"
            >
              Use
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
