import type { Character, ComputedStats, SkillKey } from '@/types';
import { skills } from '@/data';
import { useCharacterStore } from '@/store/characterStore';

interface Props {
  character: Character;
  stats: ComputedStats;
}

function formatMod(n: number): string {
  return n >= 0 ? `+${n}` : `${n}`;
}

export function SkillsList({ character, stats }: Props) {
  const updateCharacter = useCharacterStore(s => s.updateCharacter);

  function toggleSkill(skill: SkillKey) {
    const current = character.skillProficiencies;
    if (character.expertise.includes(skill)) {
      updateCharacter(character.id, {
        skillProficiencies: current.filter(s => s !== skill),
        expertise: character.expertise.filter(s => s !== skill),
      });
    } else if (current.includes(skill)) {
      updateCharacter(character.id, {
        expertise: [...character.expertise, skill],
      });
    } else {
      updateCharacter(character.id, {
        skillProficiencies: [...current, skill],
      });
    }
  }

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-1 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">Skills</h3>
      <div className="mb-2 flex items-center gap-3 text-[10px] text-ink-300 dark:text-ink-400">
        <span className="flex items-center gap-1"><span className="inline-block h-2.5 w-2.5 rounded-full border-2 border-ink-300 dark:border-ink-500" /> None</span>
        <span className="flex items-center gap-1"><span className="inline-block h-2.5 w-2.5 rounded-full bg-crimson dark:bg-crimson-light" /> Prof</span>
        <span className="flex items-center gap-1"><span className="inline-block h-2.5 w-2.5 rounded-full bg-gold dark:bg-gold-light" /> Expert</span>
      </div>
      <div className="space-y-0.5">
        {skills.map(skill => {
          const proficient = character.skillProficiencies.includes(skill.key);
          const expert = character.expertise.includes(skill.key);
          return (
            <div key={skill.key} className="flex items-center gap-2 text-sm">
              <button
                onClick={() => toggleSkill(skill.key)}
                className={`h-4 w-4 shrink-0 rounded-full border-2 transition-colors ${
                  expert
                    ? 'border-gold bg-gold dark:border-gold-light dark:bg-gold-light'
                    : proficient
                    ? 'border-crimson bg-crimson dark:border-crimson-light dark:bg-crimson-light'
                    : 'border-ink-300 bg-white hover:border-ink-400 dark:border-ink-500 dark:bg-ink-700'
                }`}
                title={expert ? 'Expertise (click to remove)' : proficient ? 'Proficient (click for expertise)' : 'Not proficient (click to add)'}
              />
              <span className="w-8 text-right font-semibold text-ink-700 dark:text-parchment-100">{formatMod(stats.skills[skill.key])}</span>
              <span className="text-ink-500 dark:text-parchment-300">{skill.name}</span>
              <span className="text-[10px] uppercase text-ink-300 dark:text-ink-400">{skill.ability}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
