import { useState } from 'react';
import type { Character, ComputedStats, AbilityKey } from '@/types';
import { abilities } from '@/data';
import { useCharacterStore } from '@/store/characterStore';
import { Dices } from 'lucide-react';

interface Props {
  character: Character;
  stats: ComputedStats;
}

function formatMod(n: number): string {
  return n >= 0 ? `+${n}` : `${n}`;
}

interface SaveRollResult {
  ability: string;
  rolls: number[];
  total: number;
  detail: string;
  autoFail?: boolean;
}

// Conditions that auto-fail STR and DEX saves
const AUTO_FAIL_CONDITIONS = ['paralyzed', 'stunned', 'unconscious'];
// Conditions that give disadvantage on DEX saves
const DEX_SAVE_DISADVANTAGE = ['restrained'];

export function SavingThrows({ character, stats }: Props) {
  const updateCharacter = useCharacterStore(s => s.updateCharacter);
  const [lastRoll, setLastRoll] = useState<SaveRollResult | null>(null);

  function toggleSave(ability: AbilityKey) {
    const current = character.saveProficiencies;
    const updated = current.includes(ability)
      ? current.filter(a => a !== ability)
      : [...current, ability];
    updateCharacter(character.id, { saveProficiencies: updated });
  }

  function isAutoFail(ability: AbilityKey): boolean {
    if (ability !== 'str' && ability !== 'dex') return false;
    return character.conditions.some(c => AUTO_FAIL_CONDITIONS.includes(c));
  }

  function getSaveDisadvantage(ability: AbilityKey): boolean {
    if (ability === 'dex' && character.conditions.some(c => DEX_SAVE_DISADVANTAGE.includes(c))) return true;
    return false;
  }

  function rollSave(ability: AbilityKey, name: string) {
    if (isAutoFail(ability)) {
      setLastRoll({
        ability: name,
        rolls: [0],
        total: 0,
        detail: 'Auto-fail (paralyzed/stunned/unconscious)',
        autoFail: true,
      });
      return;
    }

    const bonus = stats.savingThrows[ability];
    const hasDisadvantage = getSaveDisadvantage(ability);
    const d20a = Math.floor(Math.random() * 20) + 1;
    const d20b = Math.floor(Math.random() * 20) + 1;

    let used: number;
    let rolls: number[];
    if (hasDisadvantage) {
      used = Math.min(d20a, d20b);
      rolls = [d20a, d20b];
    } else {
      used = d20a;
      rolls = [d20a];
    }

    const total = used + bonus;
    const rollDetail = rolls.length > 1
      ? `d20(${rolls.join(', ')} → ${used}) DIS`
      : `d20(${used})`;

    setLastRoll({
      ability: name,
      rolls,
      total,
      detail: `${rollDetail} ${bonus >= 0 ? '+' : ''}${bonus}`,
    });
  }

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-2 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">Saving Throws</h3>
      <div className="space-y-1">
        {abilities.map(({ key, name }) => {
          const proficient = character.saveProficiencies.includes(key as AbilityKey);
          const autoFail = isAutoFail(key as AbilityKey);
          const hasDisadvantage = getSaveDisadvantage(key as AbilityKey);

          return (
            <div key={key} className="flex items-center gap-2 text-sm">
              <button
                onClick={() => toggleSave(key as AbilityKey)}
                className={`h-4 w-4 shrink-0 rounded-full border-2 transition-colors ${
                  proficient ? 'border-crimson bg-crimson dark:border-crimson-light dark:bg-crimson-light' : 'border-ink-300 bg-white hover:border-ink-400 dark:border-ink-500 dark:bg-ink-700'
                }`}
              />
              <span className="w-8 text-right font-semibold text-ink-700 dark:text-parchment-100">{formatMod(stats.savingThrows[key as AbilityKey])}</span>
              <span className="flex-1 text-ink-500 dark:text-parchment-300">{name}</span>
              {autoFail && (
                <span className="text-[9px] font-bold text-crimson dark:text-crimson-light" title="Auto-fail from condition">FAIL</span>
              )}
              {hasDisadvantage && !autoFail && (
                <span className="text-[9px] font-bold text-gold dark:text-gold-light" title="Disadvantage from condition">DIS</span>
              )}
              <button
                onClick={() => rollSave(key as AbilityKey, name)}
                className="rounded p-0.5 text-ink-300 transition-colors hover:bg-parchment-100 hover:text-ink-500 dark:text-ink-400 dark:hover:bg-ink-600 dark:hover:text-parchment-200"
                title={autoFail ? 'Auto-fail' : `Roll ${name} save`}
              >
                <Dices className="h-3.5 w-3.5" />
              </button>
            </div>
          );
        })}
      </div>

      {/* Roll result */}
      {lastRoll && (
        <div className={`mt-2 rounded-lg p-2 text-center ${
          lastRoll.autoFail
            ? 'bg-crimson/10 border border-crimson/30 dark:bg-crimson-light/10 dark:border-crimson-light/30'
            : 'bg-parchment-100 dark:bg-ink-700'
        }`}>
          <div className="text-xs font-semibold uppercase text-ink-500 dark:text-parchment-300">
            {lastRoll.ability} Save
          </div>
          <div className={`text-xl font-bold ${lastRoll.autoFail ? 'text-crimson dark:text-crimson-light' : 'text-ink-800 dark:text-parchment-100'}`}>
            {lastRoll.autoFail ? 'AUTO-FAIL' : lastRoll.total}
          </div>
          <div className="text-xs text-ink-400 dark:text-parchment-400">
            {lastRoll.detail}
          </div>
        </div>
      )}
    </div>
  );
}
