import { useCharacterStore } from '@/store/characterStore';
import { conditions as conditionsData } from '@/data';
import type { Character, ConditionKey } from '@/types';

interface Props {
  character: Character;
}

const CONDITION_EFFECTS: Record<string, string> = {
  blinded: 'Disadvantage on attacks. Attacks against you have advantage.',
  charmed: "Can't attack the charmer. Charmer has advantage on social checks.",
  deafened: 'Auto-fails hearing checks.',
  frightened: 'Disadvantage on attacks & ability checks while source in sight.',
  grappled: 'Speed 0.',
  incapacitated: "Can't take actions or reactions.",
  invisible: 'Advantage on attacks. Attacks against you have disadvantage.',
  paralyzed: "Auto-fail STR/DEX saves. Attacks against have advantage. Hits within 5ft are crits.",
  petrified: 'Resistance to all damage. Immune to poison/disease.',
  poisoned: 'Disadvantage on attacks & ability checks.',
  prone: 'Disadvantage on attacks. Melee attacks against have advantage; ranged have disadvantage.',
  restrained: 'Speed 0. Disadvantage on attacks & DEX saves. Attacks against have advantage.',
  stunned: "Auto-fail STR/DEX saves. Attacks against have advantage.",
  unconscious: "Auto-fail STR/DEX saves. Attacks have advantage. Hits within 5ft are crits. Falls prone.",
  exhaustion: 'Cumulative penalties per level. Level 6 = death.',
};

export function Conditions({ character }: Props) {
  const toggleCondition = useCharacterStore(s => s.toggleCondition);
  const activeConditions = character.conditions;

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-2 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">Conditions</h3>
      <div className="flex flex-wrap gap-1.5">
        {conditionsData.map(cond => {
          const active = activeConditions.includes(cond.key as ConditionKey);
          return (
            <button
              key={cond.key}
              onClick={() => toggleCondition(character.id, cond.key as ConditionKey)}
              title={cond.description}
              className={`rounded-full px-2.5 py-1 text-xs font-medium transition-colors ${
                active
                  ? 'bg-crimson text-white dark:bg-crimson-light'
                  : 'bg-ink-100/60 text-ink-400 hover:bg-ink-100 hover:text-ink-600 dark:bg-ink-600 dark:text-parchment-300 dark:hover:bg-ink-500 dark:hover:text-parchment-100'
              }`}
            >
              {cond.name}
            </button>
          );
        })}
      </div>

      {/* Active condition effects summary */}
      {activeConditions.length > 0 && (
        <div className="mt-2 space-y-1">
          {activeConditions.map(key => {
            const effect = CONDITION_EFFECTS[key];
            const cond = conditionsData.find(c => c.key === key);
            if (!effect || !cond) return null;
            return (
              <div key={key} className="rounded bg-crimson/5 px-2 py-1 text-[11px] dark:bg-crimson-light/10">
                <span className="font-semibold text-crimson dark:text-crimson-light">{cond.name}:</span>
                <span className="ml-1 text-ink-500 dark:text-parchment-300">{effect}</span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
