import { useCharacterStore } from '@/store/characterStore';
import type { Character } from '@/types';
import { Skull, RotateCcw } from 'lucide-react';

interface Props {
  character: Character;
}

export function DeathSaves({ character }: Props) {
  const { addDeathSave, resetDeathSaves } = useCharacterStore();

  if (character.hp.current > 0) return null;

  return (
    <div className="rounded-xl border border-crimson/30 bg-crimson/5 p-4 shadow-sm dark:border-crimson-light/30 dark:bg-crimson-light/10">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Skull className="h-4 w-4 text-crimson dark:text-crimson-light" />
          <h3 className="text-xs font-semibold uppercase tracking-wider text-crimson dark:text-crimson-light">Death Saves</h3>
        </div>
        <button onClick={() => resetDeathSaves(character.id)} className="text-ink-400 hover:text-ink-600 dark:text-parchment-300 dark:hover:text-parchment-100">
          <RotateCcw className="h-3.5 w-3.5" />
        </button>
      </div>

      <div className="mt-2 flex gap-6">
        <div>
          <span className="text-xs font-medium text-emerald-dark dark:text-emerald-light">Successes</span>
          <div className="mt-1 flex gap-1">
            {[0, 1, 2].map(i => (
              <button
                key={i}
                onClick={() => addDeathSave(character.id, 'success')}
                className={`h-5 w-5 rounded-full border-2 transition-colors ${
                  i < character.deathSaves.successes
                    ? 'border-emerald-dark bg-emerald-dark dark:border-emerald-light dark:bg-emerald-light'
                    : 'border-emerald-dark/40 hover:border-emerald-dark dark:border-emerald-light/40 dark:hover:border-emerald-light'
                }`}
              />
            ))}
          </div>
        </div>
        <div>
          <span className="text-xs font-medium text-crimson dark:text-crimson-light">Failures</span>
          <div className="mt-1 flex gap-1">
            {[0, 1, 2].map(i => (
              <button
                key={i}
                onClick={() => addDeathSave(character.id, 'failure')}
                className={`h-5 w-5 rounded-full border-2 transition-colors ${
                  i < character.deathSaves.failures
                    ? 'border-crimson bg-crimson dark:border-crimson-light dark:bg-crimson-light'
                    : 'border-crimson/40 hover:border-crimson dark:border-crimson-light/40 dark:hover:border-crimson-light'
                }`}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
