import { useState } from 'react';
import { useCharacterStore } from '@/store/characterStore';
import type { Character } from '@/types';
import { Heart, ShieldPlus, Minus, Plus } from 'lucide-react';

interface Props {
  character: Character;
}

export function HitPoints({ character }: Props) {
  const { takeDamage, heal, addTempHP, updateCharacter } = useCharacterStore();
  const [amount, setAmount] = useState('');
  const numAmount = parseInt(amount) || 0;

  const hpPercent = character.hp.max > 0 ? (character.hp.current / character.hp.max) * 100 : 0;
  const barColor = hpPercent > 50 ? 'bg-emerald-dark dark:bg-emerald-light' : hpPercent > 25 ? 'bg-gold dark:bg-gold-light' : 'bg-crimson dark:bg-crimson-light';

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-2 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">Hit Points</h3>

      <div className="flex items-center gap-3">
        <Heart className="h-6 w-6 text-crimson dark:text-crimson-light" />
        <div className="flex-1">
          <div className="flex items-baseline gap-1">
            <span className="text-4xl font-bold leading-none text-ink-800 dark:text-parchment-100">{character.hp.current}</span>
            <span className="text-lg text-ink-400 dark:text-parchment-400">/</span>
            <input
              type="number"
              value={character.hp.max}
              onChange={e => updateCharacter(character.id, { hp: { ...character.hp, max: parseInt(e.target.value) || 0 } })}
              className="w-14 border-none bg-transparent text-lg font-semibold text-ink-500 outline-none dark:text-parchment-200"
            />
          </div>
          <div className="mt-1 h-2 w-full overflow-hidden rounded-full bg-ink-100 dark:bg-ink-600">
            <div
              className={`h-full rounded-full transition-all duration-300 ${barColor}`}
              style={{ width: `${Math.min(100, hpPercent)}%` }}
            />
          </div>
        </div>
        {character.hp.temp > 0 && (
          <div className="flex flex-col items-center rounded bg-royal-blue/10 px-2 py-1 dark:bg-royal-light/20">
            <ShieldPlus className="h-3 w-3 text-royal-blue dark:text-royal-light" />
            <span className="text-sm font-bold text-royal-blue dark:text-royal-light">+{character.hp.temp}</span>
            <span className="text-[8px] uppercase text-royal-blue/70 dark:text-royal-light/70">Temp</span>
          </div>
        )}
      </div>

      <div className="mt-3 flex items-center gap-2">
        <input
          type="number"
          value={amount}
          onChange={e => setAmount(e.target.value)}
          placeholder="HP"
          min="0"
          className="w-16 rounded border border-ink-200 bg-white px-2 py-1.5 text-center text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
        />
        <button
          onClick={() => { if (numAmount > 0) { takeDamage(character.id, numAmount); setAmount(''); } }}
          className="flex items-center gap-1 rounded bg-crimson/10 px-3 py-1.5 text-sm font-medium text-crimson transition-colors hover:bg-crimson/20 dark:bg-crimson-light/20 dark:text-crimson-light"
        >
          <Minus className="h-3 w-3" /> Damage
        </button>
        <button
          onClick={() => { if (numAmount > 0) { heal(character.id, numAmount); setAmount(''); } }}
          className="flex items-center gap-1 rounded bg-emerald-dark/10 px-3 py-1.5 text-sm font-medium text-emerald-dark transition-colors hover:bg-emerald-dark/20 dark:bg-emerald-light/20 dark:text-emerald-light"
        >
          <Plus className="h-3 w-3" /> Heal
        </button>
        <button
          onClick={() => { if (numAmount > 0) { addTempHP(character.id, numAmount); setAmount(''); } }}
          className="flex items-center gap-1 rounded bg-royal-blue/10 px-3 py-1.5 text-sm font-medium text-royal-blue transition-colors hover:bg-royal-blue/20 dark:bg-royal-light/20 dark:text-royal-light"
        >
          <ShieldPlus className="h-3 w-3" /> Temp
        </button>
      </div>
    </div>
  );
}
