import { useState } from 'react';
import { useCharacterStore, createDefaultCharacter, getDefaultSpellSlots } from '@/store/characterStore';
import { races, classes, backgrounds, abilities, alignments, skills as skillsData, deities, deitySettings } from '@/data';
import type { Character, AbilityKey, SkillKey } from '@/types';
import { ArrowLeft, ArrowRight, Check, Dices } from 'lucide-react';

type Step = 'race' | 'class' | 'background' | 'abilities' | 'skills' | 'details';
const STEPS: Step[] = ['race', 'class', 'background', 'abilities', 'skills', 'details'];
const STEP_LABELS: Record<Step, string> = {
  race: 'Race',
  class: 'Class',
  background: 'Background',
  abilities: 'Ability Scores',
  skills: 'Skills',
  details: 'Details',
};

const STANDARD_ARRAY = [15, 14, 13, 12, 10, 8];
const POINT_BUY_COSTS: Record<number, number> = { 8: 0, 9: 1, 10: 2, 11: 3, 12: 4, 13: 5, 14: 7, 15: 9 };
const POINT_BUY_BUDGET = 27;

function rollDie(rerollOnes: boolean): number {
  let result = Math.floor(Math.random() * 6) + 1;
  if (rerollOnes) {
    while (result === 1) {
      result = Math.floor(Math.random() * 6) + 1;
    }
  }
  return result;
}

function roll4d6DropLowest(rerollOnes: boolean): { total: number; dice: number[]; kept: number[] } {
  const dice = [rollDie(rerollOnes), rollDie(rerollOnes), rollDie(rerollOnes), rollDie(rerollOnes)];
  const sorted = [...dice].sort((a, b) => b - a);
  const kept = sorted.slice(0, 3);
  const total = kept.reduce((sum, d) => sum + d, 0);
  return { total, dice, kept };
}

interface RollResult {
  total: number;
  dice: number[];
  kept: number[];
}

interface Props {
  onFinish: () => void;
  onCancel: () => void;
}

export function CharacterCreation({ onFinish, onCancel }: Props) {
  const { createCharacter } = useCharacterStore();
  const [step, setStep] = useState(0);
  const [draft, setDraft] = useState<Partial<Character>>(createDefaultCharacter());
  const [abilityMethod, setAbilityMethod] = useState<'standard' | 'pointbuy' | 'manual' | 'rolled'>('standard');
  const [standardAssignment, setStandardAssignment] = useState<Record<AbilityKey, number | null>>({
    str: null, dex: null, con: null, int: null, wis: null, cha: null,
  });
  const [rerollOnes, setRerollOnes] = useState(false);
  const [rolledPool, setRolledPool] = useState<RollResult[]>([]);
  const [rolledAssignment, setRolledAssignment] = useState<Record<AbilityKey, number | null>>({
    str: null, dex: null, con: null, int: null, wis: null, cha: null,
  });

  const [deitySetting, setDeitySetting] = useState<string>('Forgotten Realms');

  const currentStep = STEPS[step];
  const race = races.find(r => r.key === draft.raceKey);
  const cls = classes.find(c => c.key === draft.classKey);
  const bg = backgrounds.find(b => b.key === draft.backgroundKey);

  function update(partial: Partial<Character>) {
    setDraft(d => ({ ...d, ...partial }));
  }

  function usedStandardValues(): number[] {
    return Object.values(standardAssignment).filter((v): v is number => v !== null);
  }

  function pointBuyTotal(): number {
    if (!draft.abilities) return 0;
    return Object.values(draft.abilities).reduce((sum, v) => sum + (POINT_BUY_COSTS[v] ?? 0), 0);
  }

  function finish() {
    // Apply class defaults
    const classData = classes.find(c => c.key === draft.classKey);
    const bgData = backgrounds.find(b => b.key === draft.backgroundKey);
    const raceData = races.find(r => r.key === draft.raceKey);

    // Merge class skill picks + background skills (deduped)
    const bgSkills = bgData?.skillProficiencies ?? [];
    const allSkills = [...new Set([...(draft.skillProficiencies ?? []), ...bgSkills])];

    const finalDraft: Partial<Character> = {
      ...draft,
      skillProficiencies: allSkills,
      saveProficiencies: classData?.savingThrows ?? [],
      armorProficiencies: classData?.armorProficiencies ?? [],
      weaponProficiencies: classData?.weaponProficiencies ?? [],
      toolProficiencies: [
        ...(classData?.toolProficiencies ?? []),
        ...(bgData?.toolProficiencies ?? []),
      ],
      languages: raceData?.languages.filter(l => !l.startsWith('+')) ?? ['Common'],
      speed: raceData?.speed ?? 30,
      classes: [{
        classKey: draft.classKey ?? 'fighter',
        subclassKey: draft.subclassKey ?? null,
        classLevel: 1,
        hitDiceCurrent: 1,
      }],
      hitDice: { current: 1, max: 1 },
      hp: {
        current: (classData?.hitDie ?? 8) + Math.floor(((draft.abilities?.con ?? 10) - 10) / 2),
        max: (classData?.hitDie ?? 8) + Math.floor(((draft.abilities?.con ?? 10) - 10) / 2),
        temp: 0,
      },
      pactSlots: null,
      spellSlots: getDefaultSpellSlots(draft.classKey ?? 'fighter', draft.level ?? 1, draft.subclassKey),
    };

    createCharacter(finalDraft);
    onFinish();
  }

  return (
    <div className="mx-auto max-w-3xl">
      {/* Step indicator */}
      <div className="mb-6 space-y-2">
        <div className="flex items-center justify-between">
          <button onClick={onCancel} className="text-sm text-ink-400 hover:text-ink-600 dark:text-parchment-300 dark:hover:text-parchment-100">
            <ArrowLeft className="mr-1 inline h-4 w-4" /> Back to roster
          </button>
        </div>
        <div className="flex flex-wrap justify-center gap-1">
          {STEPS.map((s, i) => (
            <button
              key={s}
              onClick={() => setStep(i)}
              className={`rounded-full px-3 py-1 text-xs font-medium transition-colors ${
                i === step
                  ? 'bg-crimson text-white'
                  : i < step
                  ? 'bg-emerald-dark/10 text-emerald-dark'
                  : 'bg-ink-100 text-ink-400 dark:bg-ink-600 dark:text-parchment-400'
              }`}
            >
              {STEP_LABELS[s]}
            </button>
          ))}
        </div>
      </div>

      <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80 min-h-[400px]">
        {/* RACE */}
        {currentStep === 'race' && (
          <div>
            <h2 className="mb-4 text-xl font-bold text-ink-800 dark:text-parchment-100">Choose a Race</h2>
            <div className="grid grid-cols-3 gap-3">
              {races.map(r => (
                <button
                  key={r.key}
                  onClick={() => update({ raceKey: r.key, subraceKey: r.key === 'human' ? null : (r.subraces?.[0]?.key ?? null) })}
                  className={`rounded-lg border-2 p-3 text-left transition-colors ${
                    draft.raceKey === r.key
                      ? 'border-crimson bg-crimson/5'
                      : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                  }`}
                >
                  <div className="font-semibold text-ink-700 dark:text-parchment-100">{r.name}</div>
                  <div className="mt-0.5 text-xs text-ink-400 dark:text-parchment-400">
                    Speed {r.speed} ft &middot; {r.size}
                  </div>
                  <div className="mt-1 text-xs text-ink-400">
                    {Object.entries(r.abilityScoreIncrease)
                      .filter(([k]) => k !== 'choice')
                      .map(([k, v]) => `${(k as string).toUpperCase()} +${v}`)
                      .join(', ')}
                  </div>
                </button>
              ))}
            </div>
            {/* Subrace */}
            {race?.subraces && race.subraces.length > 0 && (
              <div className="mt-4">
                <h3 className="mb-2 text-sm font-semibold text-ink-500 dark:text-parchment-300">Subrace</h3>
                <div className="grid grid-cols-2 gap-2">
                  {/* Standard option for races where subrace is optional (e.g. Human) */}
                  {draft.raceKey === 'human' && (
                    <button
                      onClick={() => update({ subraceKey: null })}
                      className={`rounded-lg border-2 p-3 text-left transition-colors ${
                        draft.subraceKey === null
                          ? 'border-crimson bg-crimson/5'
                          : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                      }`}
                    >
                      <div className="font-semibold text-sm text-ink-700 dark:text-parchment-100">Standard Human</div>
                      <div className="mt-1 text-xs text-ink-400 dark:text-parchment-400">
                        +1 to all ability scores
                      </div>
                    </button>
                  )}
                  {race.subraces.map(sub => {
                    const bonuses = Object.entries(sub.abilityScoreIncrease)
                      .filter(([k]) => k !== 'choice')
                      .map(([k, v]) => `${k.toUpperCase()} +${v}`)
                      .join(', ');
                    return (
                      <button
                        key={sub.key}
                        onClick={() => update({ subraceKey: sub.key })}
                        className={`rounded-lg border-2 p-3 text-left transition-colors ${
                          draft.subraceKey === sub.key
                            ? 'border-crimson bg-crimson/5'
                            : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                        }`}
                      >
                        <div className="font-semibold text-sm text-ink-700 dark:text-parchment-100">{sub.name}</div>
                        {bonuses && (
                          <div className="mt-1 text-xs text-ink-400 dark:text-parchment-400">{bonuses}</div>
                        )}
                        {sub.traits.length > 0 && (
                          <div className="mt-1 text-xs text-ink-300 dark:text-ink-400">
                            {sub.traits.map(t => t.name).join(', ')}
                          </div>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Draconic Ancestry picker for Dragonborn */}
            {draft.raceKey === 'dragonborn' && (
              <div className="mt-4">
                <h3 className="mb-2 text-sm font-semibold text-ink-500 dark:text-parchment-300">Draconic Ancestry</h3>
                <p className="mb-2 text-xs text-ink-400 dark:text-parchment-400">Choose your dragon ancestor. This determines your breath weapon and damage resistance.</p>
                <div className="grid grid-cols-2 gap-2">
                  {[
                    { type: 'Black', damage: 'Acid', breath: '5×30 ft line', save: 'DEX' },
                    { type: 'Blue', damage: 'Lightning', breath: '5×30 ft line', save: 'DEX' },
                    { type: 'Brass', damage: 'Fire', breath: '5×30 ft line', save: 'DEX' },
                    { type: 'Bronze', damage: 'Lightning', breath: '5×30 ft line', save: 'DEX' },
                    { type: 'Copper', damage: 'Acid', breath: '5×30 ft line', save: 'DEX' },
                    { type: 'Gold', damage: 'Fire', breath: '15 ft cone', save: 'DEX' },
                    { type: 'Green', damage: 'Poison', breath: '15 ft cone', save: 'CON' },
                    { type: 'Red', damage: 'Fire', breath: '15 ft cone', save: 'DEX' },
                    { type: 'Silver', damage: 'Cold', breath: '15 ft cone', save: 'CON' },
                    { type: 'White', damage: 'Cold', breath: '15 ft cone', save: 'CON' },
                  ].map(d => (
                    <button
                      key={d.type}
                      onClick={() => update({ draconicAncestry: d.type })}
                      className={`rounded-lg border-2 p-2 text-left text-sm transition-colors ${
                        draft.draconicAncestry === d.type
                          ? 'border-crimson bg-crimson/5'
                          : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                      }`}
                    >
                      <span className="font-semibold text-ink-700 dark:text-parchment-100">{d.type}</span>
                      <div className="mt-0.5 text-xs text-ink-400 dark:text-parchment-400">
                        {d.damage} &middot; {d.breath} &middot; {d.save} save
                      </div>
                    </button>
                  ))}
                </div>
                <div className="mt-2 rounded border border-ink-100 bg-parchment-50 p-2 text-xs text-ink-500 dark:border-ink-600 dark:bg-ink-700 dark:text-parchment-300">
                  <strong>Breath Weapon:</strong> Use your action to exhale destructive energy. DC = 8 + CON mod + proficiency bonus. Damage: 2d6 at 1st level, 3d6 at 6th, 4d6 at 11th, 5d6 at 16th. Recharges on short or long rest.
                  <br /><strong>Damage Resistance:</strong> You have resistance to your ancestry's damage type.
                </div>
              </div>
            )}
          </div>
        )}

        {/* CLASS */}
        {currentStep === 'class' && (
          <div>
            <h2 className="mb-4 text-xl font-bold text-ink-800 dark:text-parchment-100">Choose a Class</h2>
            <div className="grid grid-cols-3 gap-3">
              {classes.map(c => (
                <button
                  key={c.key}
                  onClick={() => update({ classKey: c.key, subclassKey: null })}
                  className={`rounded-lg border-2 p-3 text-left transition-colors ${
                    draft.classKey === c.key
                      ? 'border-crimson bg-crimson/5'
                      : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                  }`}
                >
                  <div className="font-semibold text-ink-700 dark:text-parchment-100">{c.name}</div>
                  <div className="mt-0.5 text-xs text-ink-400">
                    d{c.hitDie} &middot; {c.savingThrows.map(s => s.toUpperCase()).join(', ')} saves
                  </div>
                  {c.spellcasting && (
                    <div className="mt-0.5 text-xs text-royal-blue dark:text-royal-light">{c.spellcasting.type} caster</div>
                  )}
                  {c.subclassLevel && (
                    <div className="mt-0.5 text-[10px] text-ink-300 dark:text-ink-400">
                      {c.subclasses[0]?.flavor ?? 'Subclass'} at lvl {c.subclassLevel}
                    </div>
                  )}
                </button>
              ))}
            </div>

            {/* Subclass selection for level 1 subclass classes */}
            {cls?.subclassLevel === 1 && cls.subclasses.length > 0 && (
              <div className="mt-4">
                <h3 className="mb-2 text-sm font-semibold text-ink-500 dark:text-parchment-300">
                  {cls.subclasses[0]?.flavor ?? 'Subclass'}
                </h3>
                <div className="space-y-2">
                  {cls.subclasses.map(sub => (
                    <button
                      key={sub.key}
                      onClick={() => update({ subclassKey: sub.key })}
                      className={`w-full rounded-lg border-2 p-3 text-left transition-colors ${
                        draft.subclassKey === sub.key
                          ? 'border-crimson bg-crimson/5'
                          : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                      }`}
                    >
                      <div className="font-semibold text-ink-700 dark:text-parchment-100">{sub.name}</div>
                      {sub.description && (
                        <p className="mt-1 text-xs leading-relaxed text-ink-500 dark:text-parchment-300">{sub.description}</p>
                      )}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* BACKGROUND */}
        {currentStep === 'background' && (
          <div>
            <h2 className="mb-4 text-xl font-bold text-ink-800 dark:text-parchment-100">Choose a Background</h2>
            <div className="grid grid-cols-3 gap-3">
              {backgrounds.map(b => (
                <button
                  key={b.key}
                  onClick={() => update({ backgroundKey: b.key })}
                  className={`rounded-lg border-2 p-3 text-left transition-colors ${
                    draft.backgroundKey === b.key
                      ? 'border-crimson bg-crimson/5'
                      : 'border-ink-200 hover:border-ink-300 dark:border-ink-600 dark:hover:border-ink-500'
                  }`}
                >
                  <div className="font-semibold text-ink-700 dark:text-parchment-100">{b.name}</div>
                  <div className="mt-0.5 text-xs text-ink-400">
                    {b.skillProficiencies.map(s => {
                      const sd = skillsData.find(sk => sk.key === s);
                      return sd?.name ?? s;
                    }).join(', ')}
                  </div>
                  <div className="mt-1 text-xs text-ink-500 font-medium">{b.feature.name}</div>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ABILITY SCORES */}
        {currentStep === 'abilities' && (
          <div>
            <h2 className="mb-4 text-xl font-bold text-ink-800 dark:text-parchment-100">Ability Scores</h2>
            <div className="mb-4 flex flex-wrap gap-2">
              {(['standard', 'rolled', 'pointbuy', 'manual'] as const).map(method => (
                <button
                  key={method}
                  onClick={() => {
                    setAbilityMethod(method);
                    if (method === 'standard') {
                      setStandardAssignment({ str: null, dex: null, con: null, int: null, wis: null, cha: null });
                    }
                    if (method === 'rolled') {
                      setRolledPool([]);
                      setRolledAssignment({ str: null, dex: null, con: null, int: null, wis: null, cha: null });
                      update({ abilities: { str: 10, dex: 10, con: 10, int: 10, wis: 10, cha: 10 } });
                    }
                    if (method === 'pointbuy' || method === 'manual') {
                      update({ abilities: { str: 8, dex: 8, con: 8, int: 8, wis: 8, cha: 8 } });
                    }
                  }}
                  className={`rounded-lg border-2 px-4 py-2 text-sm font-medium transition-colors ${
                    abilityMethod === method ? 'border-crimson text-crimson' : 'border-ink-200 text-ink-500 dark:border-ink-600 dark:text-parchment-300'
                  }`}
                >
                  {method === 'standard' ? 'Standard Array' : method === 'rolled' ? '4d6 Drop Lowest' : method === 'pointbuy' ? 'Point Buy' : 'Manual'}
                </button>
              ))}
            </div>

            {abilityMethod === 'pointbuy' && (
              <div className="mb-3 text-sm text-ink-500 dark:text-parchment-300">
                Points: <strong className={pointBuyTotal() > POINT_BUY_BUDGET ? 'text-crimson' : 'text-emerald-dark dark:text-emerald-light'}>
                  {pointBuyTotal()}</strong> / {POINT_BUY_BUDGET}
              </div>
            )}

            {abilityMethod === 'rolled' && (
              <div className="mb-4">
                {/* Roll controls */}
                <div className="flex flex-wrap items-center gap-3">
                  <button
                    onClick={() => {
                      const pool = Array.from({ length: 6 }, () => roll4d6DropLowest(rerollOnes));
                      setRolledPool(pool);
                      setRolledAssignment({ str: null, dex: null, con: null, int: null, wis: null, cha: null });
                      update({ abilities: { str: 10, dex: 10, con: 10, int: 10, wis: 10, cha: 10 } });
                    }}
                    className="flex items-center gap-2 rounded-lg bg-crimson px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-crimson/90 dark:bg-crimson-light dark:hover:bg-crimson-light/90"
                  >
                    <Dices className="h-4 w-4" />
                    {rolledPool.length > 0 ? 'Reroll All' : 'Roll 6 Sets'}
                  </button>
                  <label className="flex items-center gap-2 text-sm text-ink-500 dark:text-parchment-300 cursor-pointer select-none">
                    <input
                      type="checkbox"
                      checked={rerollOnes}
                      onChange={e => setRerollOnes(e.target.checked)}
                      className="h-4 w-4 rounded border-ink-300 accent-crimson"
                    />
                    Reroll 1s
                  </label>
                </div>

                {/* Rolled pool display */}
                {rolledPool.length > 0 && (
                  <div className="mt-3">
                    <p className="mb-2 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">
                      Your Rolls {Object.values(rolledAssignment).every(v => v !== null) ? '— All assigned!' : '— assign below'}
                    </p>
                    <div className="flex flex-wrap gap-2">
                      {rolledPool.map((roll, idx) => {
                        const assigned = Object.values(rolledAssignment).includes(idx);
                        const assignedTo = Object.entries(rolledAssignment).find(([, v]) => v === idx)?.[0] as AbilityKey | undefined;
                        return (
                          <div
                            key={idx}
                            className={`flex flex-col items-center rounded-lg border-2 px-3 py-2 transition-colors ${
                              assigned
                                ? 'border-emerald-dark/40 bg-emerald-dark/5 dark:border-emerald-light/40 dark:bg-emerald-light/10'
                                : 'border-ink-200 bg-white dark:border-ink-600 dark:bg-ink-700'
                            }`}
                          >
                            <span className="text-xl font-bold text-ink-800 dark:text-parchment-100">{roll.total}</span>
                            <div className="mt-1 flex gap-0.5">
                              {(() => {
                                const sorted = [...roll.dice].sort((a, b) => a - b);
                                const droppedValue = sorted[0];
                                let droppedUsed = false;
                                return roll.dice.map((d, i) => {
                                  const isDropped = !droppedUsed && d === droppedValue;
                                  if (isDropped) droppedUsed = true;
                                  return (
                                    <span
                                      key={i}
                                      className={`flex h-4 w-4 items-center justify-center rounded text-[9px] font-bold ${
                                        isDropped
                                          ? 'bg-ink-100 text-ink-300 line-through dark:bg-ink-600 dark:text-ink-400'
                                          : 'bg-crimson/10 text-crimson dark:bg-crimson-light/20 dark:text-crimson-light'
                                      }`}
                                    >
                                      {d}
                                    </span>
                                  );
                                });
                              })()}
                            </div>
                            {assigned && assignedTo && (
                              <span className="mt-1 text-[10px] font-semibold uppercase text-emerald-dark dark:text-emerald-light">
                                {assignedTo}
                              </span>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            )}

            <div className="grid grid-cols-3 gap-3 sm:grid-cols-6">
              {abilities.map(({ key, name }) => (
                <div key={key} className="flex flex-col items-center rounded-lg border border-ink-200 p-3 dark:border-ink-600">
                  <span className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">{name.slice(0, 3)}</span>

                  {abilityMethod === 'standard' ? (
                    <select
                      value={standardAssignment[key as AbilityKey] ?? ''}
                      onChange={e => {
                        const val = e.target.value ? Number(e.target.value) : null;
                        const newAssignment = { ...standardAssignment, [key]: val };
                        setStandardAssignment(newAssignment);
                        const newAbilities = { ...draft.abilities } as Record<AbilityKey, number>;
                        for (const [k, v] of Object.entries(newAssignment)) {
                          newAbilities[k as AbilityKey] = v ?? 10;
                        }
                        update({ abilities: newAbilities });
                      }}
                      className="mt-2 w-full rounded border border-ink-200 bg-white p-1 text-center text-lg font-bold outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
                    >
                      <option value="">—</option>
                      {STANDARD_ARRAY.filter(v => v === standardAssignment[key as AbilityKey] || !usedStandardValues().includes(v)).map(v => (
                        <option key={v} value={v}>{v}</option>
                      ))}
                    </select>
                  ) : abilityMethod === 'rolled' ? (
                    <div className="mt-1 flex flex-col items-center">
                      {rolledPool.length === 0 ? (
                        <span className="text-xs text-ink-300 dark:text-ink-400">Roll first</span>
                      ) : (
                        <>
                          <select
                            value={rolledAssignment[key as AbilityKey] ?? ''}
                            onChange={e => {
                              const poolIdx = e.target.value === '' ? null : Number(e.target.value);
                              const newAssignment = { ...rolledAssignment, [key]: poolIdx };
                              setRolledAssignment(newAssignment);
                              const newAbilities = { ...draft.abilities } as Record<AbilityKey, number>;
                              for (const [k, v] of Object.entries(newAssignment)) {
                                newAbilities[k as AbilityKey] = v !== null ? rolledPool[v].total : 10;
                              }
                              update({ abilities: newAbilities });
                            }}
                            className="mt-1 w-full rounded border border-ink-200 bg-white p-1 text-center text-lg font-bold outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
                          >
                            <option value="">—</option>
                            {rolledPool.map((roll, idx) => {
                              const usedBy = Object.entries(rolledAssignment).find(([, v]) => v === idx)?.[0];
                              const available = !usedBy || usedBy === key;
                              if (!available) return null;
                              return <option key={idx} value={idx}>{roll.total}</option>;
                            })}
                          </select>
                          {rolledAssignment[key as AbilityKey] !== null && (
                            <div className="mt-1 flex gap-0.5">
                              {(() => {
                                const roll = rolledPool[rolledAssignment[key as AbilityKey]!];
                                const sorted = [...roll.dice].sort((a, b) => a - b);
                                const droppedValue = sorted[0];
                                let droppedUsed = false;
                                return roll.dice.map((d, i) => {
                                  const isDropped = !droppedUsed && d === droppedValue;
                                  if (isDropped) droppedUsed = true;
                                  return (
                                    <span
                                      key={i}
                                      className={`flex h-4 w-4 items-center justify-center rounded text-[9px] font-bold ${
                                        isDropped
                                          ? 'bg-ink-100 text-ink-300 line-through dark:bg-ink-600 dark:text-ink-400'
                                          : 'bg-crimson/10 text-crimson dark:bg-crimson-light/20 dark:text-crimson-light'
                                      }`}
                                    >
                                      {d}
                                    </span>
                                  );
                                });
                              })()}
                            </div>
                          )}
                        </>
                      )}
                    </div>
                  ) : (
                    <div className="mt-2 flex items-center gap-1">
                      {(abilityMethod === 'pointbuy') && (
                        <button
                          onClick={() => {
                            const current = draft.abilities?.[key as AbilityKey] ?? 8;
                            if (current > 8) update({ abilities: { ...draft.abilities!, [key]: current - 1 } });
                          }}
                          className="rounded bg-ink-100 px-1.5 py-0.5 text-xs font-bold text-ink-500 hover:bg-ink-200 dark:bg-ink-600 dark:text-parchment-300 dark:hover:bg-ink-500"
                        >−</button>
                      )}
                      <input
                        type="number"
                        value={draft.abilities?.[key as AbilityKey] ?? 10}
                        onChange={e => update({ abilities: { ...draft.abilities!, [key]: parseInt(e.target.value) || 8 } })}
                        className="w-12 rounded border border-ink-200 bg-white p-1 text-center text-lg font-bold outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
                        min={abilityMethod === 'pointbuy' ? 8 : 1}
                        max={abilityMethod === 'pointbuy' ? 15 : 30}
                        readOnly={abilityMethod === 'pointbuy'}
                      />
                      {(abilityMethod === 'pointbuy') && (
                        <button
                          onClick={() => {
                            const current = draft.abilities?.[key as AbilityKey] ?? 8;
                            if (current < 15) update({ abilities: { ...draft.abilities!, [key]: current + 1 } });
                          }}
                          className="rounded bg-ink-100 px-1.5 py-0.5 text-xs font-bold text-ink-500 hover:bg-ink-200 dark:bg-ink-600 dark:text-parchment-300 dark:hover:bg-ink-500"
                        >+</button>
                      )}
                    </div>
                  )}

                  <span className="mt-1 text-sm font-semibold text-crimson">
                    {(() => {
                      const base = draft.abilities?.[key as AbilityKey] ?? 10;
                      const mod = Math.floor((base - 10) / 2);
                      return mod >= 0 ? `+${mod}` : `${mod}`;
                    })()}
                  </span>
                </div>
              ))}
            </div>

            {/* Racial ability score bonuses note */}
            {race && (() => {
              const subrace = race.subraces?.find(s => s.key === draft.subraceKey);
              const raceBonuses = Object.entries(race.abilityScoreIncrease)
                .filter(([k, v]) => k !== 'choice' && typeof v === 'number')
                .map(([k, v]) => `${k.toUpperCase()} +${v}`);
              const subBonuses = subrace
                ? Object.entries(subrace.abilityScoreIncrease)
                    .filter(([, v]) => typeof v === 'number')
                    .map(([k, v]) => `${k.toUpperCase()} +${v}`)
                : [];
              const allBonuses = [...raceBonuses, ...subBonuses];
              if (allBonuses.length === 0) return null;
              const label = subrace ? subrace.name : race.name;
              return (
                <div className="mt-3 rounded-lg bg-gold/5 px-3 py-2 text-xs text-ink-500 dark:bg-gold-light/10 dark:text-parchment-300">
                  <span className="font-semibold text-gold dark:text-gold-light">{label}</span>
                  {' will add '}
                  <span className="font-semibold text-ink-700 dark:text-parchment-100">{allBonuses.join(', ')}</span>
                  {' to your final scores.'}
                </div>
              );
            })()}
          </div>
        )}

        {/* SKILLS */}
        {currentStep === 'skills' && (
          <div>
            <h2 className="mb-2 text-xl font-bold text-ink-800 dark:text-parchment-100">Choose Skills</h2>
            {cls && (
              <p className="mb-4 text-sm text-ink-400">
                Choose {cls.skillChoices.count} skills
                {cls.skillChoices.from === 'any' ? ' from any skill' : ` from: ${(cls.skillChoices.from as SkillKey[]).map(s => skillsData.find(sk => sk.key === s)?.name ?? s).join(', ')}`}
              </p>
            )}
            {bg && (
              <p className="mb-4 text-sm text-ink-400">
                Background grants: {bg.skillProficiencies.map(s => skillsData.find(sk => sk.key === s)?.name ?? s).join(', ')}
              </p>
            )}
            <div className="grid grid-cols-2 gap-2 sm:grid-cols-3">
              {skillsData.map(skill => {
                const fromBackground = bg?.skillProficiencies.includes(skill.key) ?? false;
                const classAvailable = cls?.skillChoices.from === 'any' || (cls?.skillChoices.from as SkillKey[])?.includes(skill.key);
                const selected = draft.skillProficiencies?.includes(skill.key) ?? false;
                const classCount = (draft.skillProficiencies ?? []).filter(s => !(bg?.skillProficiencies.includes(s))).length;
                const maxClassSkills = cls?.skillChoices.count ?? 2;

                return (
                  <button
                    key={skill.key}
                    onClick={() => {
                      if (fromBackground) return;
                      const current = draft.skillProficiencies ?? [];
                      if (selected) {
                        update({ skillProficiencies: current.filter(s => s !== skill.key) });
                      } else if (classAvailable && classCount < maxClassSkills) {
                        update({ skillProficiencies: [...current, skill.key] });
                      }
                    }}
                    disabled={fromBackground}
                    className={`rounded-lg border-2 px-3 py-2 text-left text-sm transition-colors ${
                      fromBackground
                        ? 'border-emerald-dark/30 bg-emerald-dark/5 text-emerald-dark'
                        : selected
                        ? 'border-crimson bg-crimson/5 text-crimson'
                        : classAvailable
                        ? 'border-ink-300 text-ink-700 hover:border-ink-400 hover:bg-parchment-50 dark:border-parchment-400/40 dark:text-parchment-100 dark:hover:border-parchment-300 dark:hover:bg-ink-600'
                        : 'border-ink-100 text-ink-300/50 opacity-40 dark:border-ink-600 dark:text-ink-500'
                    }`}
                  >
                    <span className="font-medium">{skill.name}</span>
                    <span className="ml-1 text-xs uppercase">({skill.ability})</span>
                    {fromBackground && <span className="ml-1 text-[10px]">(background)</span>}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* DETAILS */}
        {currentStep === 'details' && (
          <div>
            <h2 className="mb-4 text-xl font-bold text-ink-800 dark:text-parchment-100">Character Details</h2>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Character Name</label>
                <input
                  type="text"
                  value={draft.name ?? ''}
                  onChange={e => update({ name: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
                  placeholder="Gandalf the Grey"
                />
              </div>
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Player Name</label>
                <input
                  type="text"
                  value={draft.playerName ?? ''}
                  onChange={e => update({ playerName: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
                />
              </div>
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Alignment</label>
                <select
                  value={draft.alignment ?? ''}
                  onChange={e => update({ alignment: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
                >
                  {alignments.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
              </div>
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Deity</label>
                <div className="mt-1 flex gap-1">
                  <select
                    value={deitySetting}
                    onChange={e => setDeitySetting(e.target.value)}
                    className="w-1/3 rounded border border-ink-200 bg-white px-2 py-2 text-xs outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
                  >
                    {deitySettings.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                  <select
                    value={draft.deity ?? ''}
                    onChange={e => update({ deity: e.target.value })}
                    className="flex-1 rounded border border-ink-200 bg-white px-2 py-2 text-sm outline-none dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100"
                  >
                    <option value="">— None —</option>
                    {deities
                      .filter(d => d.setting === deitySetting)
                      .sort((a, b) => a.name.localeCompare(b.name))
                      .map(d => <option key={d.name} value={d.name}>{d.name} — {d.title}</option>)}
                  </select>
                </div>
                {draft.deity && (() => {
                  const d = deities.find(dt => dt.name === draft.deity);
                  if (!d) return null;
                  return (
                    <div className="mt-1 rounded border border-ink-100 bg-parchment-50 p-1.5 text-xs text-ink-500 dark:border-ink-600 dark:bg-ink-700 dark:text-parchment-300">
                      <span className="font-medium text-ink-600 dark:text-parchment-200">{d.name}</span> — {d.title}
                      {' · '}{d.alignment}{' · '}{d.domains.join(', ') || 'No domain'}{' · '}{d.symbol}
                    </div>
                  );
                })()}
              </div>
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Age</label>
                <input
                  type="text"
                  value={draft.age ?? ''}
                  onChange={e => update({ age: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
                />
              </div>
            </div>
            <div className="mt-4 space-y-3">
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Personality Traits</label>
                <textarea
                  value={draft.personalityTraits ?? ''}
                  onChange={e => update({ personalityTraits: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
                  rows={2}
                />
              </div>
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Ideals</label>
                <textarea
                  value={draft.ideals ?? ''}
                  onChange={e => update({ ideals: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
                  rows={2}
                />
              </div>
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Bonds</label>
                <textarea
                  value={draft.bonds ?? ''}
                  onChange={e => update({ bonds: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
                  rows={2}
                />
              </div>
              <div>
                <label className="text-xs font-semibold uppercase text-ink-400 dark:text-parchment-400">Flaws</label>
                <textarea
                  value={draft.flaws ?? ''}
                  onChange={e => update({ flaws: e.target.value })}
                  className="mt-1 w-full rounded border border-ink-200 bg-white px-3 py-2 text-sm outline-none focus:border-crimson dark:border-ink-500 dark:bg-ink-700 dark:text-parchment-100 dark:focus:border-crimson-light"
                  rows={2}
                />
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Navigation */}
      <div className="mt-4 flex justify-between">
        <button
          onClick={() => setStep(s => Math.max(0, s - 1))}
          disabled={step === 0}
          className="flex items-center gap-1 rounded-lg border border-ink-200 px-4 py-2 text-sm font-medium text-ink-600 transition-colors hover:bg-parchment-50 disabled:opacity-40 dark:border-ink-600 dark:text-parchment-200 dark:hover:bg-ink-700"
        >
          <ArrowLeft className="h-4 w-4" /> Previous
        </button>
        {step < STEPS.length - 1 ? (
          <button
            onClick={() => setStep(s => Math.min(STEPS.length - 1, s + 1))}
            className="flex items-center gap-1 rounded-lg bg-crimson px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-crimson/90"
          >
            Next <ArrowRight className="h-4 w-4" />
          </button>
        ) : (
          <button
            onClick={finish}
            className="flex items-center gap-1 rounded-lg bg-emerald-dark px-6 py-2 text-sm font-medium text-white transition-colors hover:bg-emerald-dark/90"
          >
            <Check className="h-4 w-4" /> Create Character
          </button>
        )}
      </div>
    </div>
  );
}
