import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { AbilityKey, SkillKey } from '@/types';

// ---- Custom Content Types ----

export interface CustomSpell {
  id: string;
  name: string;
  level: number;
  school: string;
  castingTime: string;
  range: string;
  components: string;
  duration: string;
  classes: string[]; // class keys like 'sorcerer', 'wizard'
  ritual: boolean;
  concentration: boolean;
  description: string;
}

export interface CustomSubclassFeature {
  name: string;
  level: number;
  description: string;
}

export interface CustomSubclass {
  id: string;
  classKey: string; // which class this belongs to
  name: string;
  flavor: string; // e.g. "Sorcerous Origin", "Divine Domain"
  description: string;
  features: CustomSubclassFeature[];
}

export interface CustomRace {
  id: string;
  name: string;
  size: string;
  speed: number;
  abilityScoreIncrease: Partial<Record<AbilityKey, number>>;
  languages: string[];
  traits: { name: string; description: string }[];
}

export interface CustomSubrace {
  id: string;
  raceKey: string; // which existing race this attaches to (e.g. 'dwarf', 'elf')
  name: string;
  description: string;
  abilityScoreIncrease: Partial<Record<AbilityKey, number>>;
  traits: { name: string; description: string }[];
}

export interface CustomBackground {
  id: string;
  name: string;
  skillProficiencies: SkillKey[];
  toolProficiencies: string[];
  languages: string | null;
  equipment: string[];
  featureName: string;
  featureDescription: string;
}

export interface CustomContentStore {
  spells: CustomSpell[];
  subclasses: CustomSubclass[];
  subraces: CustomSubrace[];
  races: CustomRace[];
  backgrounds: CustomBackground[];

  addSpell: (spell: Omit<CustomSpell, 'id'>) => void;
  updateSpell: (id: string, spell: Partial<CustomSpell>) => void;
  deleteSpell: (id: string) => void;

  addSubclass: (subclass: Omit<CustomSubclass, 'id'>) => void;
  updateSubclass: (id: string, subclass: Partial<CustomSubclass>) => void;
  deleteSubclass: (id: string) => void;

  addSubrace: (subrace: Omit<CustomSubrace, 'id'>) => void;
  updateSubrace: (id: string, subrace: Partial<CustomSubrace>) => void;
  deleteSubrace: (id: string) => void;

  addRace: (race: Omit<CustomRace, 'id'>) => void;
  updateRace: (id: string, race: Partial<CustomRace>) => void;
  deleteRace: (id: string) => void;

  addBackground: (bg: Omit<CustomBackground, 'id'>) => void;
  updateBackground: (id: string, bg: Partial<CustomBackground>) => void;
  deleteBackground: (id: string) => void;

  exportAll: () => string;
  importAll: (json: string) => boolean;
}

function genId() { return crypto.randomUUID(); }

export const useCustomContentStore = create<CustomContentStore>()(
  persist(
    (set, get) => ({
      spells: [],
      subclasses: [],
      subraces: [],
      races: [],
      backgrounds: [],

      addSpell: (spell) => set(s => ({ spells: [...s.spells, { ...spell, id: genId() }] })),
      updateSpell: (id, updates) => set(s => ({ spells: s.spells.map(sp => sp.id === id ? { ...sp, ...updates } : sp) })),
      deleteSpell: (id) => set(s => ({ spells: s.spells.filter(sp => sp.id !== id) })),

      addSubclass: (subclass) => set(s => ({ subclasses: [...s.subclasses, { ...subclass, id: genId() }] })),
      updateSubclass: (id, updates) => set(s => ({ subclasses: s.subclasses.map(sc => sc.id === id ? { ...sc, ...updates } : sc) })),
      deleteSubclass: (id) => set(s => ({ subclasses: s.subclasses.filter(sc => sc.id !== id) })),

      addSubrace: (subrace) => set(s => ({ subraces: [...s.subraces, { ...subrace, id: genId() }] })),
      updateSubrace: (id, updates) => set(s => ({ subraces: s.subraces.map(sr => sr.id === id ? { ...sr, ...updates } : sr) })),
      deleteSubrace: (id) => set(s => ({ subraces: s.subraces.filter(sr => sr.id !== id) })),

      addRace: (race) => set(s => ({ races: [...s.races, { ...race, id: genId() }] })),
      updateRace: (id, updates) => set(s => ({ races: s.races.map(r => r.id === id ? { ...r, ...updates } : r) })),
      deleteRace: (id) => set(s => ({ races: s.races.filter(r => r.id !== id) })),

      addBackground: (bg) => set(s => ({ backgrounds: [...s.backgrounds, { ...bg, id: genId() }] })),
      updateBackground: (id, updates) => set(s => ({ backgrounds: s.backgrounds.map(b => b.id === id ? { ...b, ...updates } : b) })),
      deleteBackground: (id) => set(s => ({ backgrounds: s.backgrounds.filter(b => b.id !== id) })),

      exportAll: () => {
        const { spells, subclasses, subraces, races, backgrounds } = get();
        return JSON.stringify({ spells, subclasses, subraces, races, backgrounds }, null, 2);
      },
      importAll: (json) => {
        try {
          const data = JSON.parse(json);
          set({
            spells: data.spells ?? [],
            subclasses: data.subclasses ?? [],
            subraces: data.subraces ?? [],
            races: data.races ?? [],
            backgrounds: data.backgrounds ?? [],
          });
          return true;
        } catch { return false; }
      },
    }),
    { name: 'dnd-custom-content' }
  )
);
