import { useState } from 'react';
import type { Character, ComputedStats, EquippedWeaponStats, ConditionKey } from '@/types';
import { Swords, Dices } from 'lucide-react';

interface Props {
  character: Character;
  stats: ComputedStats;
}

interface RollResult {
  type: 'attack' | 'damage';
  weaponName: string;
  rolls: number[];
  total: number;
  detail: string;
  isCrit?: boolean;
  mode?: 'normal' | 'advantage' | 'disadvantage';
}

function rollDie(sides: number): number {
  return Math.floor(Math.random() * sides) + 1;
}

function rollDice(notation: string): { total: number; rolls: number[]; sides: number } {
  const match = notation.match(/(\d+)d(\d+)/);
  if (!match) return { total: 0, rolls: [], sides: 0 };
  const count = parseInt(match[1]);
  const sides = parseInt(match[2]);
  const rolls: number[] = [];
  for (let i = 0; i < count; i++) rolls.push(rollDie(sides));
  return { total: rolls.reduce((s, r) => s + r, 0), rolls, sides };
}

// Determine if conditions force advantage or disadvantage on attacks
function getConditionAttackMode(conditions: ConditionKey[]): 'advantage' | 'disadvantage' | null {
  const hasDisadvantage = conditions.some(c =>
    ['blinded', 'frightened', 'poisoned', 'prone', 'restrained'].includes(c)
  );
  const hasAdvantage = conditions.includes('invisible');
  if (hasAdvantage && hasDisadvantage) return null; // cancel out
  if (hasAdvantage) return 'advantage';
  if (hasDisadvantage) return 'disadvantage';
  return null;
}

function WeaponCard({ weapon, rollMode, onRoll }: {
  weapon: EquippedWeaponStats;
  rollMode: 'normal' | 'advantage' | 'disadvantage';
  onRoll: (result: RollResult) => void;
}) {
  function handleAttackRoll() {
    const d20a = rollDie(20);
    const d20b = rollDie(20);
    let used: number;
    let rolls: number[];
    if (rollMode === 'advantage') {
      used = Math.max(d20a, d20b);
      rolls = [d20a, d20b];
    } else if (rollMode === 'disadvantage') {
      used = Math.min(d20a, d20b);
      rolls = [d20a, d20b];
    } else {
      used = d20a;
      rolls = [d20a];
    }
    const isCrit = used === 20;
    const total = used + weapon.attackBonus;
    const modeLabel = rollMode === 'advantage' ? ' ADV' : rollMode === 'disadvantage' ? ' DIS' : '';
    const rollDetail = rolls.length > 1
      ? `d20(${rolls.join(', ')} → ${used})${modeLabel}`
      : `d20(${used})`;
    onRoll({
      type: 'attack',
      weaponName: weapon.name,
      rolls,
      total,
      detail: `${rollDetail} ${weapon.attackBonus >= 0 ? '+' : ''}${weapon.attackBonus}`,
      isCrit,
      mode: rollMode,
    });
  }

  function handleDamageRoll() {
    const dmgMatch = weapon.damage.match(/(\d+d\d+)/);
    if (!dmgMatch) return;
    const { total: diceTotal, rolls } = rollDice(dmgMatch[1]);
    const modMatch = weapon.damage.match(/([+-]\s*\d+)/);
    const mod = modMatch ? parseInt(modMatch[1].replace(/\s/g, '')) : 0;
    let total = Math.max(1, diceTotal + mod);
    let detail = `${dmgMatch[1]}(${rolls.join(',')}) ${mod >= 0 ? '+' : ''}${mod} ${weapon.damageType}`;

    // Roll bonus damage dice (Flame Tongue fire, etc.)
    if (weapon.bonusDamage) {
      for (const bd of weapon.bonusDamage) {
        const { total: bdTotal, rolls: bdRolls } = rollDice(bd.dice);
        total += bdTotal;
        detail += ` + ${bd.dice}(${bdRolls.join(',')}) ${bd.type}`;
      }
    }

    onRoll({
      type: 'damage',
      weaponName: weapon.name,
      rolls,
      total,
      detail,
    });
  }

  const isSpellAttack = weapon.name.startsWith('Spell Attack');

  return (
    <div className={`flex items-center gap-2 rounded-lg border p-2 ${
      isSpellAttack
        ? 'border-purple-300/50 bg-purple-50/60 dark:border-purple-500/30 dark:bg-purple-900/20'
        : 'border-ink-200/50 bg-white/60 dark:border-ink-600 dark:bg-ink-700/60'
    }`}>
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-1">
          <span className="font-semibold text-sm text-ink-700 dark:text-parchment-100 truncate">{weapon.name}</span>
          {!isSpellAttack && (
            <span className={`text-[9px] font-bold uppercase rounded px-1 ${
              weapon.slot === 'mainhand' ? 'bg-crimson/10 text-crimson dark:bg-crimson-light/20 dark:text-crimson-light'
                : 'bg-royal-blue/10 text-royal-blue dark:bg-royal-light/20 dark:text-royal-light'
            }`}>{weapon.slot === 'mainhand' ? 'MH' : 'OH'}</span>
          )}
          {!weapon.isProficient && (
            <span className="text-[9px] text-ink-300 dark:text-ink-400" title="Not proficient">✗</span>
          )}
        </div>
        <div className="text-[10px] text-ink-400 dark:text-parchment-400">
          {isSpellAttack ? 'Spell attack roll (damage varies by spell)' : weapon.properties.join(', ')}
        </div>
        {weapon.bonusDamage && weapon.bonusDamage.length > 0 && (
          <div className="text-[10px] text-crimson dark:text-crimson-light">
            {weapon.bonusDamage.map(bd => `+${bd.dice} ${bd.type}`).join(', ')}
          </div>
        )}
      </div>
      <button
        onClick={handleAttackRoll}
        className="flex flex-col items-center rounded bg-parchment-100 px-2 py-1 transition-colors hover:bg-parchment-200 dark:bg-ink-600 dark:hover:bg-ink-500"
        title="Roll attack"
      >
        <span className="text-[9px] font-semibold uppercase text-ink-400 dark:text-parchment-400">Atk</span>
        <span className="text-sm font-bold text-ink-700 dark:text-parchment-100">
          {weapon.attackBonus >= 0 ? '+' : ''}{weapon.attackBonus}
        </span>
      </button>
      {!isSpellAttack && (
        <button
          onClick={handleDamageRoll}
          className="flex flex-col items-center rounded bg-parchment-100 px-2 py-1 transition-colors hover:bg-parchment-200 dark:bg-ink-600 dark:hover:bg-ink-500"
          title="Roll damage"
        >
          <span className="text-[9px] font-semibold uppercase text-ink-400 dark:text-parchment-400">Dmg</span>
          <span className="text-sm font-bold text-ink-700 dark:text-parchment-100">{weapon.damage}</span>
        </button>
      )}
    </div>
  );
}

export function WeaponAttacks({ character, stats }: Props) {
  const [lastRoll, setLastRoll] = useState<RollResult | null>(null);
  const [manualMode, setManualMode] = useState<'normal' | 'advantage' | 'disadvantage'>('normal');

  // Determine effective roll mode from conditions + manual override
  const conditionMode = getConditionAttackMode(character.conditions);
  const conditionForcing = conditionMode !== null;
  const effectiveMode = conditionForcing ? conditionMode : manualMode;

  // Get active conditions that affect attacks
  const attackConditions = character.conditions.filter(c =>
    ['blinded', 'frightened', 'poisoned', 'prone', 'restrained', 'invisible'].includes(c)
  );

  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <div className="flex items-center justify-between mb-2">
        <h3 className="flex items-center gap-1.5 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">
          <Swords className="h-3.5 w-3.5" /> Attacks
        </h3>

        {/* Advantage/Disadvantage toggle */}
        <div className="flex items-center gap-1">
          {(['normal', 'advantage', 'disadvantage'] as const).map(mode => (
            <button
              key={mode}
              onClick={() => setManualMode(mode)}
              disabled={conditionForcing}
              className={`rounded px-2 py-0.5 text-[10px] font-medium transition-colors ${
                effectiveMode === mode
                  ? mode === 'advantage'
                    ? 'bg-emerald-dark/10 text-emerald-dark dark:bg-emerald-light/20 dark:text-emerald-light'
                    : mode === 'disadvantage'
                    ? 'bg-crimson/10 text-crimson dark:bg-crimson-light/20 dark:text-crimson-light'
                    : 'bg-ink-200/50 text-ink-600 dark:bg-ink-600 dark:text-parchment-200'
                  : 'text-ink-300 hover:text-ink-500 dark:text-ink-400 dark:hover:text-parchment-300'
              } ${conditionForcing ? 'opacity-60 cursor-not-allowed' : ''}`}
            >
              {mode === 'normal' ? 'Normal' : mode === 'advantage' ? 'Adv' : 'Dis'}
            </button>
          ))}
        </div>
      </div>

      {/* Condition notice */}
      {attackConditions.length > 0 && (
        <div className={`mb-2 rounded px-2 py-1 text-[10px] ${
          effectiveMode === 'advantage'
            ? 'bg-emerald-dark/5 text-emerald-dark dark:bg-emerald-light/10 dark:text-emerald-light'
            : 'bg-crimson/5 text-crimson dark:bg-crimson-light/10 dark:text-crimson-light'
        }`}>
          {effectiveMode === 'advantage' ? 'Advantage' : 'Disadvantage'} from: {attackConditions.join(', ')}
        </div>
      )}

      <div className="space-y-2">
        {stats.equippedWeapons.map(w => (
          <WeaponCard key={`${w.slot}-${w.name}`} weapon={w} rollMode={effectiveMode} onRoll={setLastRoll} />
        ))}
      </div>

      {/* Roll result display */}
      {lastRoll && (
        <div className={`mt-2 rounded-lg p-2 text-center ${
          lastRoll.isCrit
            ? 'bg-gold/20 border border-gold dark:bg-gold-light/20 dark:border-gold-light'
            : lastRoll.type === 'attack'
            ? 'bg-parchment-100 dark:bg-ink-700'
            : 'bg-crimson/5 dark:bg-crimson-light/10'
        }`}>
          <div className="flex items-center justify-center gap-2">
            <Dices className="h-4 w-4 text-ink-400 dark:text-parchment-300" />
            <span className="text-xs font-semibold uppercase text-ink-500 dark:text-parchment-300">
              {lastRoll.weaponName} {lastRoll.type === 'attack' ? 'Attack' : 'Damage'}
              {lastRoll.isCrit && ' — CRITICAL HIT!'}
              {lastRoll.mode === 'advantage' && ' (Adv)'}
              {lastRoll.mode === 'disadvantage' && ' (Dis)'}
            </span>
          </div>
          <div className="mt-1 text-2xl font-bold text-ink-800 dark:text-parchment-100">
            {lastRoll.total}
          </div>
          <div className="text-xs text-ink-400 dark:text-parchment-400">
            {lastRoll.detail}
          </div>
        </div>
      )}
    </div>
  );
}
