/**
 * Transforms raw 5e-bits SRD JSON data into our app's type shapes.
 * Source: https://github.com/5e-bits/5e-database (SRD 5.1, OGL 1.0a)
 */

import type {
  Race, Subrace, Trait, ClassData, ClassSpellcasting, Background,
  Spell, SkillData, ConditionData, Weapon, Armor, GearItem,
  AbilityKey, SkillKey,
} from '@/types';

// ---- Raw SRD types (just enough to type the imports) ----

interface SrdRef {
  index: string;
  name: string;
  url: string;
}

interface SrdAbilityBonus {
  ability_score: SrdRef;
  bonus: number;
}

// ---- Spells ----

interface SrdSpell {
  index: string;
  name: string;
  desc: string[];
  higher_level?: string[];
  range: string;
  components: string[];
  material?: string;
  ritual: boolean;
  duration: string;
  concentration: boolean;
  casting_time: string;
  level: number;
  damage?: {
    damage_type?: SrdRef;
    damage_at_slot_level?: Record<string, string>;
    damage_at_character_level?: Record<string, string>;
  };
  dc?: {
    dc_type: SrdRef;
    dc_success: string;
  };
  heal_at_slot_level?: Record<string, string>;
  area_of_effect?: { type: string; size: number };
  school: SrdRef;
  classes: SrdRef[];
  subclasses: SrdRef[];
  attack_type?: string;
}

export function transformSpells(raw: SrdSpell[]): Spell[] {
  return raw.map(s => {
    const components = s.components.join(', ');
    const description = s.desc.join('\n\n');
    const higherLevel = s.higher_level?.join('\n\n') ?? '';
    const fullDesc = higherLevel ? `${description}\n\n**At Higher Levels.** ${higherLevel}` : description;

    return {
      name: s.name,
      level: s.level,
      school: s.school.name,
      castingTime: s.casting_time,
      range: s.range,
      components: s.material ? `${components} (${s.material})` : components,
      duration: s.duration,
      classes: s.classes.map(c => c.index),
      ritual: s.ritual,
      concentration: s.concentration,
      description: fullDesc,
    };
  });
}

// ---- Races ----

interface SrdRace {
  index: string;
  name: string;
  speed: number;
  ability_bonuses: SrdAbilityBonus[];
  ability_bonus_options?: {
    choose: number;
    from: { option_set_type: string; options: { ability_score: SrdRef; bonus: number }[] };
  };
  size: string;
  languages: SrdRef[];
  traits: SrdRef[];
  subraces: SrdRef[];
  age?: string;
  alignment?: string;
  size_description?: string;
  language_desc?: string;
}

interface SrdSubrace {
  index: string;
  name: string;
  race: SrdRef;
  desc: string;
  ability_bonuses: SrdAbilityBonus[];
  racial_traits: SrdRef[];
}

interface SrdTrait {
  index: string;
  name: string;
  desc: string[];
  races: SrdRef[];
  subraces: SrdRef[];
  proficiencies?: SrdRef[];
}

export function transformRaces(
  rawRaces: SrdRace[],
  rawSubraces: SrdSubrace[],
  rawTraits: SrdTrait[]
): Race[] {
  return rawRaces.map(r => {
    const abilityScoreIncrease: Partial<Record<AbilityKey, number>> & { choice?: string } = {};
    for (const ab of r.ability_bonuses) {
      abilityScoreIncrease[ab.ability_score.index as AbilityKey] = ab.bonus;
    }
    if (r.ability_bonus_options) {
      abilityScoreIncrease.choice = `Choose ${r.ability_bonus_options.choose} ability scores to increase by 1`;
    }

    // Find traits for this race
    const raceTraits: Trait[] = rawTraits
      .filter(t => t.races.some(tr => tr.index === r.index) && t.subraces.length === 0)
      .map(t => ({ name: t.name, description: t.desc.join(' ') }));

    // Find subraces
    const subraces: Subrace[] = rawSubraces
      .filter(sr => sr.race.index === r.index)
      .map(sr => {
        const subAbilities: Partial<Record<AbilityKey, number>> = {};
        for (const ab of sr.ability_bonuses) {
          subAbilities[ab.ability_score.index as AbilityKey] = ab.bonus;
        }

        const subTraits: Trait[] = rawTraits
          .filter(t => t.subraces.some(s => s.index === sr.index))
          .map(t => ({ name: t.name, description: t.desc.join(' ') }));

        return {
          key: sr.index,
          name: sr.name,
          abilityScoreIncrease: subAbilities,
          traits: subTraits,
        };
      });

    return {
      key: r.index,
      name: r.name,
      size: r.size,
      speed: r.speed,
      abilityScoreIncrease,
      languages: r.languages.map(l => l.name),
      traits: raceTraits,
      subraces: subraces.length > 0 ? subraces : undefined,
    };
  });
}

// ---- Classes ----

interface SrdClass {
  index: string;
  name: string;
  hit_die: number;
  proficiency_choices: {
    desc: string;
    choose: number;
    type: string;
    from: {
      option_set_type: string;
      options: { option_type: string; item: SrdRef }[];
    };
  }[];
  proficiencies: SrdRef[];
  saving_throws: SrdRef[];
  starting_equipment: { equipment: SrdRef; quantity: number }[];
  starting_equipment_options?: { desc: string }[];
  subclasses: SrdRef[];
  spellcasting?: {
    level: number;
    spellcasting_ability: SrdRef;
    info: { name: string; desc: string[] }[];
  };
}

interface SrdLevel {
  level: number;
  class: SrdRef;
  ability_score_bonuses: number;
  prof_bonus: number;
  features: SrdRef[];
  spellcasting?: Record<string, number>;
  class_specific?: Record<string, unknown>;
  subclass?: SrdRef;
}

interface SrdFeature {
  index: string;
  name: string;
  level: number;
  class: SrdRef;
  subclass?: SrdRef;
  desc: string[];
}

// Skill index to our key mapping
function skillIndexToKey(index: string): SkillKey | null {
  const map: Record<string, SkillKey> = {
    'skill-acrobatics': 'acrobatics',
    'skill-animal-handling': 'animalHandling',
    'skill-arcana': 'arcana',
    'skill-athletics': 'athletics',
    'skill-deception': 'deception',
    'skill-history': 'history',
    'skill-insight': 'insight',
    'skill-intimidation': 'intimidation',
    'skill-investigation': 'investigation',
    'skill-medicine': 'medicine',
    'skill-nature': 'nature',
    'skill-perception': 'perception',
    'skill-performance': 'performance',
    'skill-persuasion': 'persuasion',
    'skill-religion': 'religion',
    'skill-sleight-of-hand': 'sleightOfHand',
    'skill-stealth': 'stealth',
    'skill-survival': 'survival',
  };
  return map[index] ?? null;
}

function classifyProficiency(index: string): { type: 'armor' | 'weapon' | 'tool' | 'other'; name: string } {
  if (index.includes('armor') || index === 'shields') return { type: 'armor', name: index };
  if (['simple-weapons', 'martial-weapons'].includes(index)) return { type: 'weapon', name: index.replace('-weapons', '') };
  if (index.startsWith('skill-')) return { type: 'other', name: index };
  // Specific weapons
  const weaponNames = ['club', 'dagger', 'dart', 'javelin', 'mace', 'quarterstaff', 'scimitar', 'sickle', 'sling', 'spear',
    'light-crossbow', 'hand-crossbow', 'heavy-crossbow', 'longbow', 'shortbow', 'longsword', 'rapier', 'shortsword',
    'battleaxe', 'flail', 'glaive', 'greataxe', 'greatsword', 'halberd', 'lance', 'maul', 'morningstar', 'pike',
    'trident', 'war-pick', 'warhammer', 'whip', 'blowgun', 'net', 'handaxe', 'light-hammer'];
  if (weaponNames.some(w => index.includes(w))) return { type: 'weapon', name: index };
  // Check for tool-like proficiencies
  if (index.includes('tools') || index.includes('kit') || index.includes('supplies') || index.includes('vehicles') || index.includes('instrument'))
    return { type: 'tool', name: index };
  return { type: 'other', name: index };
}

interface SrdSubclass {
  index: string;
  name: string;
  class: SrdRef;
  subclass_flavor: string;
  desc: string[];
}

export function transformClasses(
  rawClasses: SrdClass[],
  rawLevels: SrdLevel[],
  rawFeatures: SrdFeature[],
  rawSubclasses: SrdSubclass[] = []
): ClassData[] {
  return rawClasses.map(c => {
    // Skill choices
    const skillChoice = c.proficiency_choices.find(pc =>
      pc.from.options.some(o => o.item?.index?.startsWith('skill-'))
    );
    let skillChoices: { count: number; from: SkillKey[] | 'any' } = { count: 2, from: [] };
    if (skillChoice) {
      const skills = skillChoice.from.options
        .map(o => skillIndexToKey(o.item.index))
        .filter((s): s is SkillKey => s !== null);
      // Bard gets "any" skills
      skillChoices = { count: skillChoice.choose, from: skills.length === 18 ? 'any' : skills };
    }

    // Proficiencies
    const armorProfs: string[] = [];
    const weaponProfs: string[] = [];
    const toolProfs: string[] = [];
    for (const p of c.proficiencies) {
      const classified = classifyProficiency(p.index);
      if (classified.type === 'armor') armorProfs.push(p.name);
      else if (classified.type === 'weapon') weaponProfs.push(p.name);
      else if (classified.type === 'tool') toolProfs.push(p.name);
    }

    // Tool proficiency choices
    const toolChoice = c.proficiency_choices.find(pc =>
      !pc.from.options.some(o => o.item?.index?.startsWith('skill-'))
    );
    if (toolChoice) {
      toolProfs.push(toolChoice.desc);
    }

    // Spellcasting
    let spellcasting: ClassSpellcasting | null = null;
    if (c.spellcasting) {
      const ability = c.spellcasting.spellcasting_ability.index as AbilityKey;
      const ritualCasting = c.spellcasting.info.some(i =>
        i.name.toLowerCase().includes('ritual')
      );
      // Determine caster type from levels data
      const classLevels = rawLevels.filter(l => l.class.index === c.index);
      const level1 = classLevels.find(l => l.level === 1);
      const level2 = classLevels.find(l => l.level === 2);
      let type: 'full' | 'half' | 'pact' = 'full';
      if (c.index === 'warlock') {
        type = 'pact';
      } else if (!level1?.spellcasting?.spell_slots_level_1 && level2?.spellcasting?.spell_slots_level_1) {
        type = 'half';
      } else if (!level1?.spellcasting?.spell_slots_level_1 && !level2?.spellcasting?.spell_slots_level_1) {
        type = 'half';
      }

      spellcasting = { ability, ritualCasting, type };
    }

    // Features by level (excluding subclass features)
    const features: Record<string, { name: string; description: string }[]> = {};
    const classFeats = rawFeatures.filter(f => f.class.index === c.index && !f.subclass);
    for (const f of classFeats) {
      const key = String(f.level);
      if (!features[key]) features[key] = [];
      features[key].push({ name: f.name, description: f.desc.join('\n\n') });
    }

    // Subclass features grouped by subclass key
    const subclassFeatures: Record<string, Record<string, { name: string; description: string }[]>> = {};
    const classSubclasses = rawSubclasses.filter(sc => sc.class.index === c.index);
    for (const sc of classSubclasses) {
      subclassFeatures[sc.index] = {};
      const scFeats = rawFeatures.filter(f => f.subclass?.index === sc.index);
      for (const f of scFeats) {
        const key = String(f.level);
        if (!subclassFeatures[sc.index][key]) subclassFeatures[sc.index][key] = [];
        subclassFeatures[sc.index][key].push({ name: f.name, description: f.desc.join('\n\n') });
      }
    }

    // Starting equipment descriptions
    const startingEquipment = c.starting_equipment.map(e =>
      e.quantity > 1 ? `${e.equipment.name} x${e.quantity}` : e.equipment.name
    );
    const startingEquipmentChoices = (c.starting_equipment_options ?? []).map(o => o.desc);

    return {
      key: c.index,
      name: c.name,
      hitDie: c.hit_die,
      primaryAbility: c.saving_throws.map(s => s.index as AbilityKey),
      savingThrows: c.saving_throws.map(s => s.index as AbilityKey),
      armorProficiencies: armorProfs,
      weaponProficiencies: weaponProfs,
      toolProficiencies: toolProfs,
      skillChoices,
      startingHP: `${c.hit_die} + Con mod`,
      startingEquipment,
      startingEquipmentChoices,
      startingGold: (() => {
        const goldTable: Record<string, { dice: string; average: number }> = {
          barbarian: { dice: '2d4 x 10', average: 50 },
          bard: { dice: '5d4 x 10', average: 125 },
          cleric: { dice: '5d4 x 10', average: 125 },
          druid: { dice: '2d4 x 10', average: 50 },
          fighter: { dice: '5d4 x 10', average: 125 },
          monk: { dice: '5d4', average: 13 },
          paladin: { dice: '5d4 x 10', average: 125 },
          ranger: { dice: '5d4 x 10', average: 125 },
          rogue: { dice: '4d4 x 10', average: 100 },
          sorcerer: { dice: '3d4 x 10', average: 75 },
          warlock: { dice: '4d4 x 10', average: 100 },
          wizard: { dice: '4d4 x 10', average: 100 },
        };
        return goldTable[c.index] ?? { dice: '5d4 x 10', average: 125 };
      })(),
      spellcasting,
      features,
      subclassLevel: (() => {
        const subFeats = rawFeatures.filter(f => f.class.index === c.index && f.subclass);
        return subFeats.length > 0 ? Math.min(...subFeats.map(f => f.level)) : null;
      })(),
      subclasses: rawSubclasses
        .filter(sc => sc.class.index === c.index)
        .map(sc => ({
          key: sc.index,
          name: sc.name,
          description: sc.desc.join('\n\n'),
          flavor: sc.subclass_flavor,
        })),
      subclassFeatures,
    };
  });
}

// ---- Backgrounds (SRD only has Acolyte, keep our extras) ----

export function transformBackgrounds(raw: {
  index: string;
  name: string;
  starting_proficiencies: SrdRef[];
  feature: { name: string; desc: string[] };
  starting_equipment: { equipment: SrdRef; quantity: number }[];
  personality_traits?: { from: { options: { string?: string }[] } };
  ideals?: { from: { options: { desc?: string }[] } };
  bonds?: { from: { options: { string?: string }[] } };
  flaws?: { from: { options: { string?: string }[] } };
}[]): Background[] {
  return raw.map(b => ({
    key: b.index,
    name: b.name,
    skillProficiencies: b.starting_proficiencies
      .map(p => skillIndexToKey(p.index))
      .filter((s): s is SkillKey => s !== null),
    toolProficiencies: b.starting_proficiencies
      .filter(p => !p.index.startsWith('skill-'))
      .map(p => p.name),
    languages: null,
    equipment: b.starting_equipment.map(e => e.equipment.name),
    feature: {
      name: b.feature.name,
      description: b.feature.desc.join(' '),
    },
  }));
}

// ---- Skills ----

export function transformSkills(raw: {
  index: string;
  name: string;
  ability_score: SrdRef;
}[]): SkillData[] {
  return raw.map(s => ({
    key: (skillIndexToKey('skill-' + s.index) ?? s.index) as SkillKey,
    name: s.name,
    ability: s.ability_score.index as AbilityKey,
  }));
}

// ---- Conditions ----

export function transformConditions(raw: {
  index: string;
  name: string;
  desc: string[];
}[]): ConditionData[] {
  return raw.map(c => ({
    key: c.index as ConditionData['key'],
    name: c.name,
    description: c.desc.join(' '),
  }));
}

// ---- Equipment ----

interface SrdEquipment {
  index: string;
  name: string;
  equipment_category: SrdRef;
  weapon_category?: string;
  weapon_range?: string;
  category_range?: string;
  cost?: { quantity: number; unit: string };
  damage?: { damage_dice: string; damage_type: SrdRef };
  range?: { normal: number; long: number | null };
  weight?: number;
  properties?: SrdRef[];
  armor_category?: string;
  armor_class?: { base: number; dex_bonus: boolean; max_bonus?: number | null };
  str_minimum?: number;
  stealth_disadvantage?: boolean;
  gear_category?: SrdRef;
  quantity?: number;
  contents?: { item: SrdRef; quantity: number }[];
}

function formatCost(cost?: { quantity: number; unit: string }): string {
  if (!cost) return '—';
  return `${cost.quantity} ${cost.unit}`;
}

export function transformEquipment(raw: SrdEquipment[]): {
  weapons: { simple_melee: Weapon[]; simple_ranged: Weapon[]; martial_melee: Weapon[]; martial_ranged: Weapon[] };
  armor: { light: Armor[]; medium: Armor[]; heavy: Armor[]; shield: Armor[] };
  adventuringGear: GearItem[];
} {
  const weapons = {
    simple_melee: [] as Weapon[],
    simple_ranged: [] as Weapon[],
    martial_melee: [] as Weapon[],
    martial_ranged: [] as Weapon[],
  };
  const armor = {
    light: [] as Armor[],
    medium: [] as Armor[],
    heavy: [] as Armor[],
    shield: [] as Armor[],
  };
  const adventuringGear: GearItem[] = [];

  for (const e of raw) {
    if (e.weapon_category && e.weapon_range) {
      const cat = e.weapon_category.toLowerCase();
      const range = e.weapon_range.toLowerCase();
      const key = `${cat}_${range}` as keyof typeof weapons;
      if (weapons[key]) {
        weapons[key].push({
          name: e.name,
          cost: formatCost(e.cost),
          damage: e.damage?.damage_dice ?? null,
          damageType: e.damage?.damage_type?.name ?? null,
          weight: e.weight ?? 0,
          properties: e.properties?.map(p => p.name) ?? [],
        });
      }
    } else if (e.armor_category) {
      const cat = e.armor_category.toLowerCase() as keyof typeof armor;
      if (armor[cat]) {
        let acStr: string;
        if (e.armor_class) {
          acStr = String(e.armor_class.base);
          if (e.armor_class.dex_bonus) {
            acStr += e.armor_class.max_bonus ? ` + Dex mod (max ${e.armor_class.max_bonus})` : ' + Dex mod';
          }
        } else {
          acStr = '+2';
        }
        armor[cat].push({
          name: e.name,
          cost: formatCost(e.cost),
          ac: acStr,
          stealthDisadvantage: e.stealth_disadvantage ?? false,
          weight: e.weight ?? 0,
          strReq: e.str_minimum ?? 0,
        });
      }
    } else {
      adventuringGear.push({
        name: e.name,
        cost: formatCost(e.cost),
        weight: e.weight ?? 0,
      });
    }
  }

  return { weapons, armor, adventuringGear };
}

// ---- Categorized equipment catalog for the inventory browser ----

export interface CatalogItem {
  name: string;
  cost: string;
  weight: number;
  detail?: string; // damage, AC, etc.
}

export interface CatalogCategory {
  label: string;
  items: CatalogItem[];
}

export function buildEquipmentCatalog(raw: SrdEquipment[]): CatalogCategory[] {
  const categories: Record<string, CatalogItem[]> = {};

  for (const e of raw) {
    let catLabel: string;
    let detail: string | undefined;

    if (e.weapon_category && e.weapon_range) {
      catLabel = `${e.weapon_category} ${e.weapon_range} Weapons`;
      const dmg = e.damage ? `${e.damage.damage_dice} ${e.damage.damage_type?.name ?? ''}` : '';
      const props = e.properties?.map(p => p.name).join(', ') ?? '';
      detail = [dmg, props].filter(Boolean).join(' — ');
    } else if (e.armor_category) {
      catLabel = `Armor — ${e.armor_category}`;
      if (e.armor_class) {
        let acStr = `AC ${e.armor_class.base}`;
        if (e.armor_class.dex_bonus) acStr += e.armor_class.max_bonus ? ` + Dex (max ${e.armor_class.max_bonus})` : ' + Dex';
        detail = acStr;
        if (e.stealth_disadvantage) detail += ', stealth disadvantage';
      } else {
        detail = 'AC +2';
      }
    } else if (e.equipment_category?.name === 'Tools') {
      catLabel = 'Tools';
    } else if (e.equipment_category?.name === 'Mounts and Vehicles') {
      catLabel = 'Mounts & Vehicles';
    } else if (e.gear_category?.name) {
      catLabel = e.gear_category.name;
    } else {
      catLabel = 'Other Gear';
    }

    if (!categories[catLabel]) categories[catLabel] = [];
    categories[catLabel].push({
      name: e.name,
      cost: formatCost(e.cost),
      weight: e.weight ?? 0,
      detail,
    });
  }

  // Sort items within each category
  for (const items of Object.values(categories)) {
    items.sort((a, b) => a.name.localeCompare(b.name));
  }

  // Sort categories in a sensible order
  const order = [
    'Simple Melee Weapons', 'Simple Ranged Weapons',
    'Martial Melee Weapons', 'Martial Ranged Weapons',
    'Armor — Light', 'Armor — Medium', 'Armor — Heavy', 'Armor — Shield',
    'Standard Gear', 'Ammunition', 'Arcane Foci', 'Druidic Foci', 'Holy Symbols',
    'Kits', 'Equipment Packs', 'Tools', 'Mounts & Vehicles', 'Trade Goods', 'Other Gear',
  ];

  return order
    .filter(label => categories[label])
    .map(label => ({ label, items: categories[label] }))
    .concat(
      Object.keys(categories)
        .filter(label => !order.includes(label))
        .sort()
        .map(label => ({ label, items: categories[label] }))
    );
}

// ---- Spell Slots from Levels ----

interface SpellSlotRow {
  [key: string]: number;
}

export function transformSpellSlots(rawLevels: SrdLevel[]): {
  fullCaster: Record<string, number[]>;
  halfCaster: Record<string, number[]>;
  thirdCaster: Record<string, number[]>;
  pactMagic: Record<string, { slots: number; slotLevel: number }>;
} {
  const fullCaster: Record<string, number[]> = {};
  const halfCaster: Record<string, number[]> = {};
  const pactMagic: Record<string, { slots: number; slotLevel: number }> = {};

  // Use wizard for full caster, paladin for half caster, warlock for pact
  const wizardLevels = rawLevels.filter(l => l.class.index === 'wizard');
  const paladinLevels = rawLevels.filter(l => l.class.index === 'paladin');
  const warlockLevels = rawLevels.filter(l => l.class.index === 'warlock');

  for (const l of wizardLevels) {
    if (l.spellcasting) {
      const sc = l.spellcasting as SpellSlotRow;
      fullCaster[String(l.level)] = [
        sc.spell_slots_level_1 ?? 0, sc.spell_slots_level_2 ?? 0,
        sc.spell_slots_level_3 ?? 0, sc.spell_slots_level_4 ?? 0,
        sc.spell_slots_level_5 ?? 0, sc.spell_slots_level_6 ?? 0,
        sc.spell_slots_level_7 ?? 0, sc.spell_slots_level_8 ?? 0,
        sc.spell_slots_level_9 ?? 0,
      ];
    }
  }

  for (const l of paladinLevels) {
    if (l.spellcasting) {
      const sc = l.spellcasting as SpellSlotRow;
      halfCaster[String(l.level)] = [
        sc.spell_slots_level_1 ?? 0, sc.spell_slots_level_2 ?? 0,
        sc.spell_slots_level_3 ?? 0, sc.spell_slots_level_4 ?? 0,
        sc.spell_slots_level_5 ?? 0,
      ];
    }
  }

  for (const l of warlockLevels) {
    if (l.spellcasting) {
      const sc = l.spellcasting as SpellSlotRow;
      // Find highest non-zero slot level
      let slotLevel = 1;
      let totalSlots = 0;
      for (let i = 9; i >= 1; i--) {
        const val = sc[`spell_slots_level_${i}`] ?? 0;
        if (val > 0 && slotLevel === 1) slotLevel = i;
        totalSlots += val;
      }
      // Warlock: all slots are at the same level
      pactMagic[String(l.level)] = { slots: totalSlots, slotLevel };
    }
  }

  // Third caster (Eldritch Knight, Arcane Trickster) - not in SRD level data, hardcoded from PHB
  const thirdCaster: Record<string, number[]> = {
    '3': [2, 0, 0, 0], '4': [3, 0, 0, 0], '5': [3, 0, 0, 0], '6': [3, 0, 0, 0],
    '7': [4, 2, 0, 0], '8': [4, 2, 0, 0], '9': [4, 2, 0, 0], '10': [4, 3, 0, 0],
    '11': [4, 3, 0, 0], '12': [4, 3, 0, 0], '13': [4, 3, 2, 0], '14': [4, 3, 2, 0],
    '15': [4, 3, 2, 0], '16': [4, 3, 3, 0], '17': [4, 3, 3, 0], '18': [4, 3, 3, 0],
    '19': [4, 3, 3, 1], '20': [4, 3, 3, 1],
  };

  return { fullCaster, halfCaster, thirdCaster, pactMagic };
}

// ---- Proficiency Bonus & XP (from Levels data) ----

export function extractProfBonusByLevel(rawLevels: SrdLevel[]): Record<string, number> {
  const result: Record<string, number> = {};
  // Use any class, they all have the same prof bonus per level
  const levels = rawLevels.filter(l => l.class.index === 'barbarian');
  for (const l of levels) {
    result[String(l.level)] = l.prof_bonus;
  }
  return result;
}

// ---- Spell Knowledge Limits (cantrips_known, spells_known per class/level) ----

export interface SpellLimits {
  cantripsKnown: number | null;
  spellsKnown: number | null;
}

export function buildSpellLimitsTable(rawLevels: SrdLevel[]): Record<string, Record<number, SpellLimits>> {
  const result: Record<string, Record<number, SpellLimits>> = {};
  for (const l of rawLevels) {
    const classKey = l.class.index;
    if (!l.spellcasting) continue;
    const sc = l.spellcasting as Record<string, number | undefined>;
    if (sc.cantrips_known === undefined && sc.spells_known === undefined) continue;
    if (!result[classKey]) result[classKey] = {};
    result[classKey][l.level] = {
      cantripsKnown: sc.cantrips_known ?? null,
      spellsKnown: sc.spells_known ?? null,
    };
  }

  // Third casters (subclass-based, not in SRD level data)
  // Eldritch Knight (fighter subclass) - uses subclass key as lookup
  result['eldritch-knight'] = {
    3: { cantripsKnown: 2, spellsKnown: 3 }, 4: { cantripsKnown: 2, spellsKnown: 4 },
    5: { cantripsKnown: 2, spellsKnown: 4 }, 6: { cantripsKnown: 2, spellsKnown: 4 },
    7: { cantripsKnown: 2, spellsKnown: 5 }, 8: { cantripsKnown: 2, spellsKnown: 6 },
    9: { cantripsKnown: 2, spellsKnown: 6 }, 10: { cantripsKnown: 3, spellsKnown: 7 },
    11: { cantripsKnown: 3, spellsKnown: 8 }, 12: { cantripsKnown: 3, spellsKnown: 8 },
    13: { cantripsKnown: 3, spellsKnown: 9 }, 14: { cantripsKnown: 3, spellsKnown: 10 },
    15: { cantripsKnown: 3, spellsKnown: 10 }, 16: { cantripsKnown: 3, spellsKnown: 11 },
    17: { cantripsKnown: 3, spellsKnown: 11 }, 18: { cantripsKnown: 3, spellsKnown: 11 },
    19: { cantripsKnown: 3, spellsKnown: 12 }, 20: { cantripsKnown: 3, spellsKnown: 13 },
  };
  // Arcane Trickster (rogue subclass)
  result['arcane-trickster'] = {
    3: { cantripsKnown: 3, spellsKnown: 3 }, 4: { cantripsKnown: 3, spellsKnown: 4 },
    5: { cantripsKnown: 3, spellsKnown: 4 }, 6: { cantripsKnown: 3, spellsKnown: 4 },
    7: { cantripsKnown: 3, spellsKnown: 5 }, 8: { cantripsKnown: 3, spellsKnown: 6 },
    9: { cantripsKnown: 3, spellsKnown: 6 }, 10: { cantripsKnown: 4, spellsKnown: 7 },
    11: { cantripsKnown: 4, spellsKnown: 8 }, 12: { cantripsKnown: 4, spellsKnown: 8 },
    13: { cantripsKnown: 4, spellsKnown: 9 }, 14: { cantripsKnown: 4, spellsKnown: 10 },
    15: { cantripsKnown: 4, spellsKnown: 10 }, 16: { cantripsKnown: 4, spellsKnown: 11 },
    17: { cantripsKnown: 4, spellsKnown: 11 }, 18: { cantripsKnown: 4, spellsKnown: 11 },
    19: { cantripsKnown: 4, spellsKnown: 12 }, 20: { cantripsKnown: 4, spellsKnown: 13 },
  };

  return result;
}
