import type { Character, ComputedStats, AbilityKey } from '@/types';
import { abilities } from '@/data';

interface Props {
  character: Character;
  stats: ComputedStats;
}

function formatMod(n: number): string {
  return n >= 0 ? `+${n}` : `${n}`;
}

export function AbilityScores({ stats }: Props) {
  return (
    <div className="rounded-xl border border-ink-200/50 bg-white/80 p-4 shadow-sm dark:border-ink-600 dark:bg-ink-800/80">
      <h3 className="mb-3 text-xs font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">Ability Scores</h3>
      <div className="grid grid-cols-6 gap-2">
        {abilities.map(({ key, name }) => (
          <div key={key} className="flex flex-col items-center rounded-lg border-2 border-ink-200 bg-white p-2 transition-colors hover:border-ink-300 dark:border-ink-600 dark:bg-ink-700 dark:hover:border-ink-500">
            <span className="text-[10px] font-semibold uppercase tracking-wider text-ink-400 dark:text-parchment-400">{name.slice(0, 3)}</span>
            <span className="mt-1 text-2xl font-bold leading-none text-crimson dark:text-crimson-light">
              {formatMod(stats.abilityModifiers[key as AbilityKey])}
            </span>
            <span className="mt-1 flex h-7 w-7 items-center justify-center rounded-full border border-ink-200 bg-parchment-50 text-xs font-semibold text-ink-600 dark:border-ink-500 dark:bg-ink-600 dark:text-parchment-200">
              {stats.abilityTotals[key as AbilityKey]}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}
