import { useState, useEffect } from 'react';
import { useCharacterStore, useActiveCharacter, computeStats } from './store/characterStore';
import { CharacterSheet } from './components/sheet/CharacterSheet';
import { CharacterRoster } from './components/roster/CharacterRoster';
import { CharacterCreation } from './components/creation/CharacterCreation';
import { CustomContentEditor } from './components/custom/CustomContentEditor';
import { Users, ChevronLeft, Moon, Sun } from 'lucide-react';

type View = 'roster' | 'sheet' | 'create' | 'custom';

export default function App() {
  const character = useActiveCharacter();
  const setActiveCharacter = useCharacterStore(s => s.setActiveCharacter);
  const [view, setView] = useState<View>('roster');
  const [dark, setDark] = useState(() => {
    const stored = localStorage.getItem('dnd-dark-mode');
    if (stored !== null) return stored === 'true';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  useEffect(() => {
    document.body.classList.toggle('dark', dark);
    localStorage.setItem('dnd-dark-mode', String(dark));
  }, [dark]);

  const handleSelectCharacter = (id: string) => {
    setActiveCharacter(id);
    setView('sheet');
  };

  const stats = character ? computeStats(character) : null;

  const DarkToggle = () => (
    <button
      onClick={() => setDark(!dark)}
      className="rounded-lg p-2 text-ink-400 transition-colors hover:bg-ink-100/50 dark:text-parchment-300 dark:hover:bg-ink-700"
    >
      {dark ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
    </button>
  );

  return (
    <div className="min-h-screen">
      {/* SW toggle */}
      <div className="border-b border-ink-200/30 bg-[#0a0a12] px-4 py-2 dark:border-ink-600">
        <a
          href="/"
          className="inline-flex items-center gap-1.5 rounded border border-[#ffd700]/30 px-3 py-1 text-[9px] font-bold tracking-wider text-[#ffd700]/70 transition-colors hover:bg-[#ffd700]/10 hover:text-[#ffd700]"
          style={{ fontFamily: "'Orbitron', 'Exo 2', monospace", letterSpacing: '1px' }}
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="h-3.5 w-3.5"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" /></svg>
          STAR WARS
        </a>
      </div>

      <div className="px-4 py-6"><div className="mx-auto max-w-7xl">
        {view === 'sheet' && character && (
          <div className="mb-4 flex items-center justify-between">
            <button
              onClick={() => setView('roster')}
              className="flex items-center gap-1 text-sm text-ink-400 transition-colors hover:text-ink-600 dark:text-parchment-300 dark:hover:text-parchment-100"
            >
              <ChevronLeft className="h-4 w-4" />
              <Users className="h-4 w-4" />
              Characters
            </button>
            <DarkToggle />
          </div>
        )}

        {view === 'roster' && (
          <div className="py-8">
            <div className="fixed right-6 top-6 z-10">
              <DarkToggle />
            </div>
            <CharacterRoster
              onCreateNew={() => setView('create')}
              onCustomContent={() => setView('custom')}
              onSelect={handleSelectCharacter}
            />
          </div>
        )}

        {view === 'create' && (
          <div className="py-6">
            <div className="fixed right-6 top-6 z-10">
              <DarkToggle />
            </div>
            <CharacterCreation
              onFinish={() => setView('sheet')}
              onCancel={() => setView('roster')}
            />
          </div>
        )}

        {view === 'custom' && (
          <div className="py-6">
            <div className="fixed right-6 top-6 z-10">
              <DarkToggle />
            </div>
            <CustomContentEditor onClose={() => setView('roster')} />
          </div>
        )}

        {view === 'sheet' && character && stats && (
          <CharacterSheet character={character} stats={stats} />
        )}

        {view === 'sheet' && !character && (
          <div className="flex h-64 items-center justify-center">
            <p className="text-ink-400 dark:text-parchment-300">No character selected.</p>
            <button onClick={() => setView('roster')} className="ml-2 text-crimson underline dark:text-crimson-light">
              Go to roster
            </button>
          </div>
        )}
      </div></div>
    </div>
  );
}
