// ---- Transformed exports ----

export const spells = transformSpells(rawSpells as never[]);
export const races = transformRaces(rawRaces as never[], rawSubraces as never[], rawTraits as never[]);
export const classes = transformClasses(rawClasses as never[], rawLevels as never[], rawFeatures as never[], rawSubclasses as never[]);

// Merge SRD backgrounds with our extras (SRD only has Acolyte)
const srdBackgrounds = transformBackgrounds(rawBackgrounds as never[]);
const extraBackgrounds = (oldBackgrounds.backgrounds as unknown as BgType[])
  .filter(b => !srdBackgrounds.some(sb => sb.key === b.key));
export const backgrounds = [...srdBackgrounds, ...extraBackgrounds];

export const skills = transformSkills(rawSkills as never[]);
export const conditions = transformConditions(rawConditions as never[]);

const eq = transformEquipment(rawEquipment as never[]);
export const weapons = eq.weapons;
export const allWeapons = [
  ...eq.weapons.simple_melee,
  ...eq.weapons.simple_ranged,
  ...eq.weapons.martial_melee,
  ...eq.weapons.martial_ranged,
];
export const armor = eq.armor;
export const adventuringGear = eq.adventuringGear;

export interface Feat {
  index: string;
  name: string;
  prerequisites: Record<string, unknown>[];
  desc: string[];
}
export const feats = rawFeats as Feat[];
export function getFeat(index: string) { return feats.find(f => f.index === index); }

export function getWeaponCategory(weaponName: string): 'simple' | 'martial' | null {
  const lower = weaponName.toLowerCase();
  if ([...weapons.simple_melee, ...weapons.simple_ranged].some(w => w.name.toLowerCase() === lower)) return 'simple';
  if ([...weapons.martial_melee, ...weapons.martial_ranged].some(w => w.name.toLowerCase() === lower)) return 'martial';
  return null;
}

export const spellSlotProgression = transformSpellSlots(rawLevels as never[]);
export const proficiencyBonusByLevel = extractProfBonusByLevel(rawLevels as never[]);
export const equipmentCatalog: CatalogCategory[] = buildEquipmentCatalog(rawEquipment as never[]);

/** Look up a catalog item by name (case-insensitive) */
export function findCatalogItem(name: string) {
  const lower = name.toLowerCase();
  for (const cat of equipmentCatalog) {
    const item = cat.items.find(i => i.name.toLowerCase() === lower);
    if (item) return item;
  }
  return null;
}
export const spellLimitsTable = buildSpellLimitsTable(rawLevels as never[]);
export type { SpellLimits };

export function getSpellLimits(classKey: string, level: number, subclassKey?: string | null): SpellLimits {
  // Check subclass-specific limits first (for third casters like EK, AT)
  if (subclassKey && spellLimitsTable[subclassKey]) {
    return spellLimitsTable[subclassKey][level] ?? { cantripsKnown: null, spellsKnown: null };
  }
  return spellLimitsTable[classKey]?.[level] ?? { cantripsKnown: null, spellsKnown: null };
}

