// Magic Items
export interface MagicItemVariant {
  label: string;                    // dropdown label, e.g. "Bonus Level"
  options: {
    name: string;                   // e.g. "+1", "Fire", "Hill Giant"
    rarity?: string;                // overrides parent rarity if different
    suffix?: string;                // appended to item name, e.g. "+1" → "Longsword +1"
    prefix?: string;                // prepended to item name
    description?: string;           // overrides/appends parent description
  }[];
}

export interface MagicItem {
  name: string;
  rarity: 'common' | 'uncommon' | 'rare' | 'very rare' | 'legendary' | 'artifact';
  type: string;           // e.g. "Weapon", "Armor", "Wondrous Item", "Potion", "Ring", "Staff", "Wand", "Rod", "Scroll"
  subtype?: string;       // e.g. "plate", "shield", "any axe", "arrow"
  attunement?: boolean | string;  // true, false, or "by a cleric", "by a spellcaster", etc.
  cursed?: boolean;       // flagged for items with a Curse section
  weight?: number;
  description: string;
  variants?: MagicItemVariant[];   // if present, opens a picker modal instead of adding directly
}
export const magicItems: MagicItem[] = rawMagicItems as MagicItem[];

