// ---- Spell damage counts by class (for Dragon Ancestor etc.) ----

const _spellDamageCache: Record<string, Record<string, number>> = {};
export function getSpellDamageCountsByClass(classKey: string): Record<string, number> {
  if (_spellDamageCache[classKey]) return _spellDamageCache[classKey];
  const counts: Record<string, number> = {};
  for (const s of rawSpells as { damage?: { damage_type?: { name: string } }; classes: { index: string }[] }[]) {
    if (!s.classes.some(c => c.index === classKey)) continue;
    const dt = s.damage?.damage_type?.name;
    if (dt) counts[dt] = (counts[dt] || 0) + 1;
  }
  _spellDamageCache[classKey] = counts;
  return counts;
}

// ---- Custom content integration ----
// These functions merge SRD data with user-created custom content at lookup time.
// The custom content store is accessed lazily to avoid circular imports.

export function getAllSpells(): Spell[] {
  const custom = useCustomContentStore.getState().spells;
  const customAsSpell: Spell[] = custom.map(c => ({
    name: c.name,
    level: c.level,
    school: c.school,
    castingTime: c.castingTime,
    range: c.range,
    components: c.components,
    duration: c.duration,
    classes: c.classes,
    ritual: c.ritual,
    concentration: c.concentration,
    description: c.description,
  }));
  return [...spells, ...customAsSpell];
}

export function getAllBackgrounds(): BgType[] {
  const custom = useCustomContentStore.getState().backgrounds;
  const customAsBg: BgType[] = custom.map(c => ({
    key: `custom-${c.id}`,
    name: c.name,
    skillProficiencies: c.skillProficiencies,
    toolProficiencies: c.toolProficiencies,
    languages: c.languages,
    equipment: c.equipment,
    feature: { name: c.featureName, description: c.featureDescription },
  }));
  return [...backgrounds, ...customAsBg];
}

export function getClassWithCustomSubclasses(classKey: string): ClassData | undefined {
  const cls = classes.find(c => c.key === classKey);
  if (!cls) return undefined;
  const customSubs = useCustomContentStore.getState().subclasses.filter(s => s.classKey === classKey);
  if (customSubs.length === 0) return cls;
  return {
    ...cls,
    subclasses: [
      ...cls.subclasses,
      ...customSubs.map(s => ({ key: `custom-${s.id}`, name: s.name, description: s.description, flavor: s.flavor })),
    ],
    subclassFeatures: {
      ...cls.subclassFeatures,
      ...Object.fromEntries(customSubs.map(s => {
        const byLevel: Record<string, { name: string; description: string }[]> = {};
        for (const f of s.features) {
          const key = String(f.level);
          if (!byLevel[key]) byLevel[key] = [];
          byLevel[key].push({ name: f.name, description: f.description });
        }
        return [`custom-${s.id}`, byLevel];
      })),
    },
  };
}

function getRaceWithCustomSubraces(key: string): RaceType | undefined {
  const race = races.find(r => r.key === key);
  if (!race) return undefined;
  const customSubs = useCustomContentStore.getState().subraces.filter(s => s.raceKey === key);
  if (customSubs.length === 0) return race;
  return {
    ...race,
    subraces: [
      ...(race.subraces ?? []),
      ...customSubs.map(s => ({
        key: `custom-${s.id}`,
        name: s.name,
        abilityScoreIncrease: s.abilityScoreIncrease as Partial<Record<AbilityKey, number>>,
        traits: s.traits,
      })),
    ],
  };
}

// ---- Lookup helpers ----

export function getRace(key: string) { return getRaceWithCustomSubraces(key); }
export function getClass(key: string) { return getClassWithCustomSubclasses(key) ?? classes.find(c => c.key === key); }
export function getBackground(key: string) { return getAllBackgrounds().find(b => b.key === key); }
export function getSkill(key: string) { return skills.find(s => s.key === key); }
export function getSpellsForClass(classKey: string) {
  return getAllSpells().filter(s => s.classes.includes(classKey));
}
