import { useState } from 'react';
import type { Character, ComputedStats } from '@/types';
import { CharacterHeader } from './CharacterHeader';
import { AbilityScores } from './AbilityScores';
import { SavingThrows } from './SavingThrows';
import { SkillsList } from './SkillsList';
import { HitPoints } from './HitPoints';
import { DeathSaves } from './DeathSaves';
import { HitDice } from './HitDice';
import { Conditions } from './Conditions';
import { SpellSlots } from './SpellSlots';
import { SpellList } from './SpellList';
import { Inventory } from './Inventory';
import { FeaturesTraits } from './FeaturesTraits';
import { RestButtons } from './RestButtons';
import { WeaponAttacks } from './WeaponAttacks';
import { Notes } from './Notes';
import { LevelUpModal } from './LevelUpModal';

interface Props {
  character: Character;
  stats: ComputedStats;
}

export function CharacterSheet({ character, stats }: Props) {
  const [showLevelUp, setShowLevelUp] = useState(false);

  return (
    <div className="space-y-4">
      <CharacterHeader character={character} stats={stats} onLevelUp={() => setShowLevelUp(true)} />

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-12">
        {/* Left Column: Abilities, Saves, Skills */}
        <div className="space-y-4 lg:col-span-3">
          <AbilityScores character={character} stats={stats} />
          <SavingThrows character={character} stats={stats} />
          <SkillsList character={character} stats={stats} />
        </div>

        {/* Center Column: Combat, Spells */}
        <div className="space-y-4 lg:col-span-5">
          <HitPoints character={character} />
          <WeaponAttacks character={character} stats={stats} />
          <DeathSaves character={character} />
          <div className="grid grid-cols-2 gap-4">
            <HitDice character={character} />
            <RestButtons character={character} />
          </div>
          <Conditions character={character} />
          <SpellSlots character={character} />
          <SpellList character={character} stats={stats} />
        </div>

        {/* Right Column: Features, Inventory, Notes */}
        <div className="space-y-4 lg:col-span-4">
          <Inventory character={character} stats={stats} />
          <FeaturesTraits character={character} />
          <Notes character={character} />
        </div>
      </div>

      {showLevelUp && (
        <LevelUpModal character={character} onClose={() => setShowLevelUp(false)} />
      )}
    </div>
  );
}
